insert into public.skk_requirements (skk_item_id, level, description)
select item.id, data.level, data.description
from (values
(1, 1, 'Purwa', 'a) dapat menjalankan tayamum dan mandinya, b) memahami syarat-syarat, rukun, dan yang membatalkan sholat'),
(1, 1, 'Madya', 'a) telah memenuhi SKK Sholat Tingkat Purwa, b) mengerti surat-surat yang dibaca dalam sholat, c) mengerti bacaan-bacaan sunnah dalam sholat'),
(1, 1, 'Utama', 'a) telah memenuhi SKK Sholat Tingkat Madya, b) mengerjakan sholat Jumat, sholat dalam perjalanan, dan sholat jenazah, c) mengerjakan sholat sunnah, rawatib, sholat Idul Fitri dan Idul Adha, serta menyelenggarakan zikir dan doa sesudah sholat fardhu'),
(1, 2, 'Purwa', 'a) tahu dan dapat melaksanakan syarat dan rukun khotib, b) dapat berkhotbah dengan sopan dan dengan bahasa yang mudah dimengerti oleh umum'),
(1, 2, 'Madya', 'a) telah memenuhi SKK Khotib Tingkat Purwa, b) pernah menjadi khotib sekurang-kurangnya 4 kali'),
(1, 2, 'Utama', 'a) telah memenuhi SKK Khotib Tingkat Madya, b) dapat berkhotbah di hadapan masa sedikitnya 40 orang sekurang-kurangnya 4 kali, c) faham akan sunnah dan sejarah khotbah'),
(1, 3, 'Purwa', 'a) telah membaca Al-Qur’an juz 1 sampai dengan juz 10, b) faham akan tajwid dan mahroj dalam membaca Al-Qur’an'),
(1, 3, 'Madya', 'a) telah memenuhi SKK Qori Tingkat Purwa, b) telah membaca Al-Qur’an sampai juz 20, c) dapat membaca surat dalam Al-Qur’an, d) memahami apa yang dibaca dengan menggunakan tafsir bahasa Indonesia'),
(1, 3, 'Utama', 'a) telah memenuhi SKK Qori Tingkat Madya, b) telah membaca Al-Qur’an tamat 30 juz, c) faham akan sejarah Al-Qur’an'),
(1, 4, 'Purwa', 'a) faham akan arti lafal adzan, b) dapat menyerukan adzan dengan lagu dan suara keras dan merdu'),
(1, 4, 'Madya', 'a) telah memenuhi SKK Muadzin Tingkat Purwa, b) dapat menyerukan adzan dengan dua macam lagu, c) menjadi muadzin di tempat tinggalnya, sedikitnya selama satu bulan'),
(1, 4, 'Utama', 'a) telah memenuhi SKK Muadzin Tingkat Madya, b) faham akan sejarah fadhilah (keutamaan dan hukum menyerukan adzan), c) menjadi muadzin di tempat tinggalnya sedikitnya selama 3 bulan'),
(1, 5, 'Purwa', 'a) telah memenuhi SKK Penabung untuk Siaga, b) seluruh atau sebagian uang yang ditabung dalam buku tabungannya adalah uang yang diperoleh dari hasil usahanya sendiri, c) dapat membantu mengurus administrasi buku-buku Tabungan Pramuka di Perindukan Siaga atau di Pasukan Penggalang'),
(1, 5, 'Madya', 'a) telah memenuhi SKK Penabung Tingkat Purwa, b) dapat menjelaskan kepada Pramuka lain cara menabung dalam bank lewat Tabanas, buku Tabungan Pramuka atau buku Tabungan Pelajar, c) dapat menjelaskan kepada Pramuka lain perbedaan antara menabung di celengan dan menabung di bank lewat Tabanas, buku Tabungan Pramuka atau buku Tabungan Pelajar'),
(1, 5, 'Utama', 'a) telah memenuhi SKK Menabung Tingkat Madya, b) dapat merencanakan, mempersiapkan, dan melaksanakan suatu sandiwara kecil atau suatu ceramah tentang menabung untuk para Pramuka atau orang lain, c) mengerti arti beberapa istilah yang biasa digunakan dalam dunia perbankan, misalnya rekening giro, deposito, sertifikat BI, cek, treveller cheque, dan sejenisnya'),
(2, 2, 'Purwa', 'a) dapat mengatur isi dan menghias suatu ruangan secara sederhana, tetapi berseni (artistik), dengan memperhatikan komposisi, bentuk dan warna ruang tamu, ruang tidur, ruang belajar, ruang makan, ruang tunggu, atau ruang lainnya, b) dapat membuat sedikitnya dua macam hiasan sederhana dari barang-barang yang ada di sekitanya, misalnya dengan menggunakan bunga kebun, kertas, batu, buah-buahan, tanaman, dahan-dahan, atau bahan lainnya, c) mengerti cara mengatur lampu penerangan dan peredaran udara (ventilasi)'),
(2, 2, 'Madya', 'a) telah memenuhi SKK Pengatur Ruangan Tingkat Purwa, b) dapat mengatur dan menghias ruangan untuk: (1) rapat, pertemuan atau konperensi, (2) perayaan sekolah, kampung, masjid atau gereja, dan lain-lain, (3) ruang istirahat, ruang rekreasi, operation room, dan lain-lain, c) (1) dapat merangkai bunga untuk meja tamu, pesta, kematian, atau penghargaan kepada orang lain, dan lain-lain, atau (2) dapat membuat sedikitnya tiga macam benda hiasan, misalnya dengan menggunakan bambu, tempayan, payung, jamur, tempurung, sabut atau kayu, dan sejenisnya'),
(2, 2, 'Utama', 'a) telah memenuhi SKK Pengatur Rumah Tingkat Madya, b) dapat mengatur dan menghias: (1) ruangan tamu pada perhelatan pernikahan atau khitanan, (2) ruang pengantin atau khitanan, (3) kursi mempelai atau panggung, dengan memperhatikan keadaan ruang, jumlah undangan, jalan untuk tamu dan pembawa konsumsi, tempat pidato, tempat pertunjukan kesenian, dan lain-lain, c) dapat memelihara dan membersihkan perabot rumahtangga supaya tahan lama dan kelihatan tetap baru, misalnya meja kursi, patung, lemari, barang-barang dari logam, gelas atau kaca, dan lain-lain, d) dapat mengatur dan mengubah ruangan pameran (etalage) sesuai dengan keadaan dan kebutuhan pada saat itu, misalnya pada peringatan 17 Agustus, pada hari ulang tahun, peringatan natal, hari raya Idul Fitri, dan lain-lain'),
(2, 3, 'Purwa', 'a) dapat menyiapkan tempat dan menghidangkan jamuan minum teh panas dengan kue ala kadarnya, b) dapat menyiapkan meja untuk menghidangkan makan pagi dengan nasi atau roti secara Eropa, dan tahu cara pengguaan sendok, garpu dan pisau pada makan pagi, c) tahu dan dapat melipat serbet makan dengan bermacam cara, d) tahu sopan santun makan dan menyajikan makanan'),
(2, 3, 'Madya', 'a) telah memenuhi SKK Pengatur Meja Makan Tingkat Purwa, b) dapat menyiapkan dan menghidangkan minuman dingin, misalnya es sirop, es cendol, es kelapa muda/kopyor, es alpukat, es buah, dan sejenisnya, c) dapat menyiapkan tempat dan meja untuk jamuan makan siang atau makan malam dengan mengingat keadaan tempat dan jumlah anggota keluarga, d) tahu guna dan dapat mengatur macam-macam alat makan, seperti piring, mangkuk, sendok, garpu, pisau, dan sejenisnya, dengan bermacam ukuran dan bentuk, e) mengatur dan menyiapkan makan untuk orang sakit (di meja atau baki/talam/ nampan)'),
(2, 3, 'Utama', 'a) telah memenuhi SKK Pengatur Meja Makan Tingkat Madya, b) dapat menyiapkan dan menghidangkan minuman khas Indonesia, misalnya bajigur, sekoteng, serbat/ronde, jahe, cerme, minuman tape, sempelak, dan sejenisnya, c) (1) dapat menyiapkan tempat dan meja secara Amerika untuk menghidangkan makan siang atau makan malam, atau (2) dapat menyiapkan tempat dan meja untuk menghidangkan makan untuk pesta makan prasmanan atau pesta kebun'),
(2, 4, 'Purwa', 'a) dapat membaca not angka dan tahu tanda-tanda serta istilah not angka, b) dapat menyanyikan dua buah lagu nasional/daerah dan dua buah lagu Pramuka, baik notasi maupun kata-katanya, c) dapat memimpin regunya untuk menyanyikan: (1) lagu Indonesia Raya, (2) dua buah lagu nasional/daerahnya, dan (3) dua buah lagu Pramuka, d) mengerti cara pemberian aba atau tanda birama dengan tangan untuk lagu-lagu yang sederhana'),
(2, 4, 'Madya', 'a) telah memenuhi SKK Pemimpin Menyanyi Tingkat Purwa, b) dapat memimpin pasukan/ambalannya untuk menyanyikan beberapa buah lagu nasional, daerah atau lagu Pramuka, yang menggunakan suara pertama (eerste stem) dan suara kedua (twede stem), c) dapat memberi tanda birama, keras, lemah, dan cepat lambatnya (tempo) menyanyikan sebuah lagu dengan menggunakan tangan, d) dapat mencari nada dasar lagu dengan garpu tala (stemvork) dan/ atau peluit nada (stemfluit)'),
(2, 4, 'Utama', 'a) telah memenuhi SKK Pemimpin Menyanyi Tingkat Madya, b) dapat memimpin suatu kelompok paduan suara yang terdiri atas sedikitnya 40 orang penyanyi dari empat jenis suara (sopran, alto, tenor dan bas), untuk menyanyikan beberapa buah lagu nasional, daerah atau lagu Pramuka, c) dapat mencari nada suara dengan berbagai alat musik, dan menguasai tangga nada, d) dapat membaca not balok (notenbalk) dan tanda-tanda/istilah not balok'),
(2, 5, 'Purwa', 'a) dapat membaca not angka dan tahu tanda-tanda serta istilah not angka, b) dapat menyanyikan lagu Kebangsaan Indonesia Raya (3 bait), 3 lagu Indonesia lainnya, dan 3 lagu Pramuka, c) dapat menyanyikan sebuah lagu, baik suara pertama maupun suara keduanya'),
(2, 5, 'Madya', 'a) telah memenuhi SKK Penyanyi Tingkat Purwa, b) dapat membaca dan menuliskan not angka, dengan menggunakan tanda-tanda dan istilah-istilah not angka, c) dapat menyanyikan: - 3 buah lagu Indonesia (lagu lama/klasik atau lagu baru/populer, baik secara perseorangan/solo, maupun dalam paduan suara/ koor), - 3 buah lagu Pramuka, dan - 3 buah lagu daerahnya sendiri, d) dapat mencari nada suara dengan garpu tala (stemvork) atau peluit nada (stemfluit) dan menggunakannya'),
(2, 5, 'Utama', 'a) telah memenuhi SKK Penyanyi Tingkat Madya, b) dapat menyanyikan: - 3 buah lagu Indonesia (jenis lagu mayor, lagu minor, baik secara perseorangan/solo, maupun dalam paduan suara/koor), - 3 buah lagu Pramuka (satu di antaranya lagu asing/luar negeri), - 3 buah lagu daerahnya sendiri, c) dapat membaca not balok (notenbalk) dan tanda-tanda/istilah not balok, d) dapat mengubah/aransemen suara kedua (tweede stem) dari sebuah lagu Indonesia'),
(2, 6, 'Purwa', 'a) mengenal sekedarnya tentang sedikitnya seorang pelukis Indonesia yang sudah terkenal, b) dapat melukis dua buah lukisan yang dipilihnya secara bebas, dari tiga macam keadaan/lukisan tentang: (1) pemandangan, (2) benda mati, (3) tanaman, manusia atau hewan, yang dilakukannya dengan mengkhayal, atau menyalin, atau membuat sketsa dari keadaan tersebut di atas yang dilihatnya. c) (1) tahu kegunaan dan dapat menggunakan sedikitnya satu macam bahan untuk melukis, misalnya berbagai macam pensil, arang, cat air, cat minyak, kapur, dan sejenisnya, atau (2) dapat menggunakan alat-alat melukis, seperti palet, macam-macam kuas, mistar, kapas, dan lain-lain'),
(2, 6, 'Madya', 'a) telah memenuhi SKK Pelukis Tingkat Purwa, b) mengenal sekedarnya tentang sedikitnya seorang pelukis terkenal di dunia, c) (1) dapat melukis barang nyata atau mencipta dari khayalannya di atas kertas atau bahan lain berukuran lebar lebih kurang 20 cm, dan panjang lebih kurang 30 cm, dan (2) dapat menggunakan sedikitnya dua macam bahan untuk melukis, misalnya kapur berwarna, cat air, cat minyak, dan lain-lain, d) mengerti dan dapat memberi keterangan sekedarnya tentang perbedaan gambar datar (dekoratif ornamen) dengan gambar tiga dimanesi, atau dengan gambar lukisan aliran naturalis, abstrak, kubisme, dan sejenisnya'),
(2, 6, 'Utama', 'a) telah memenuhi SKK Pelukis Tingkat Madya, b) dapat membuat sedikitnya dua buah lukisan datar (ornamen) dengan bentuk benda yang distilir (gestileerd), atau lukisan tiga dimensi, atau lukisan abstrak, atau lukisan menurut aliran lainnya, c) dapat melukis sedikitnya dua buah lukisan, di antara hal-hal sebagai berikut: (1) lukisan pada Kartu Lebaran, Kartu Natal, Kartu Ucapan Selamat, Kartu Undangan atau kartu lainnya, (2) lukisan/ilustrasi di majalah, surat kabar, reklame, iklan, poster, dan lain-lain, (3) gambar-gambar kurikulum, (4) gambar-gambar vignet, d) dapat melukis dengan menggunakan sisir dan sikat (spatwerk), atau dengan lem kanji (lem tepung tapioka), atau dengan kertas marmer (kertas berwarna), atau dengan bahan-bahan lainnya, e) telah menyelenggarakan pameran lukisan, baik secara perorangan maupun secara beregu (berkelompok), baik untuk dilihat oleh anggota Gerakan Pramuka sendiri atau oleh rekan satu sekolah saja, maupun untuk dilihat umum, sedikitnya dua kali'),
(2, 7, 'Purwa', 'a) dapat menggunakan dengan baik alat-alat untuk menggambar, misalnya pensil, karet penghapus, mistar, jangka, busur derajat, dan lain-lain, b) dapat menggambar benda dalam bentuk gambar datar (dua dimensi) atau tiga dimensi, sedikitnya dua buah gambar yang diberi warna dengan cat air atau diarsir dengan garis sejajar, c) mengerti tanda-tanda dan dapat memilih serta menggunakan dengan tepat: (1) macam-macam pensil (misalnya H, 2H, HB, 2B, dan sejenisnya), (2) macam-macam kuas'),
(2, 7, 'Madya', 'a) telah memenuhi SKK Juru Gambar Tingkat Purwa, b) dapat menggunakan dengan baik dan tepat: (1) pena redis, rapido, atau trekpen untuk menggambar berbagai ukuran tebal garis, (2) papan/meja gambar, mistar panjang, dan mistar segitiga, c) dapat menggambar benda dengan proyeksi ortogonal (tegak lurus), secara Eropa atau Amerika, d) dapat menggambar rebahan dari benda, dan penampang datar atau penampang tegak pada potongan/irisan tertentu'),
(2, 7, 'Utama', 'a) telah memenuhi SKK Juru Gambar Tingkat Madya, b) dapat menggunakan dengan baik mal gambar (tekenmal) untuk menggambar elips, oval, atau garis lengkung, c) dapat menggambar benda dengan menggunakan proyeksi simetris dan perbandingan ukuran tertentu, d) (1) dapat menggambar proyeksi ortogonal irisan bidang miring pada sebuah benda, dan mencari luas sesungguhnya dari irisan itu, atau (2) dapat menggambarkan cara membuka/mengupas kulit dari benda tertentu'),
(2, 8, 'Purwa', 'a) mengenal sekedarnya nama dan karya sedikitnya seorang dari dua di antara tiga kelompok di bawah ini: (1) Pujangga Baru, (2) Angkatan 45, (3) Angkatan Mutakhir, b) dapat menyusun karangan berbentuk prosa, dengan judul yang ditentukan sendiri, sebanyak 1-2 halaman ketik folio (spasi ganda), atau antara 200 – 300 patah kata (karangan dapat pula ditulis dengan tangan), c) dapat menyusun/mengarang salah satu di antara pantun atau soneta'),
(2, 8, 'Madya', 'a) telah memenuhi SKK Mengarang Tingkat Purwa, b) dapat menyusun sebuah karangan berbentuk cerita pendek atau laporan, c) mengenal ciri dan dapat membuat salah satu di antara: (1) prosa liris, (2) pantun, (3) syair/sajak'),
(2, 8, 'Utama', 'a) telah memenuhi SKK Mengarang Tingkat Madya, b) (1) dapat menyusun sebuah sajak, (2) dapat menyusun dua buah karangan yang dipilihnya di antara jenis: - novel, - cerita pendek, - essay, - kritik, - laporan kerja, - pengetahuan populer, c) dapat menyusun sinopsis sebuah sandiwara sederhana'),
(3, 1, 'Purwa', 'a) mengerti cara dan telah melakukan dengan baik, sikap berdiri, berjalan (secara cepat/lambat), start waktu berlomba gerak jalan, b) mengerti cara mencegah dan merawat lepuh di kaki, cara beristirahat selama dan sesudah gerak jalan, c) pernah mengikuti gerak jalan secara berkelompok atau perorangan sejauh 10 km untuk putra dan 8 km untuk putri, dan dilakukan sedikitnya 2 kali'),
(3, 1, 'Madya', 'a) telah memenuhi SKK Gerak Jalan Tingkat Purwa, b) mengerti cara dan telah melakukan pengaturan nafas, langkah, dan peraturan-peraturan yang berlaku bagi lomba gerak jalan umumnya c) pernah mengikuti gerak jalan secara berkelompok atau perorangan sejauh 15 km untuk putra dan 12 km untuk putri, dan dilakukan sedikitnya 2 kali, d) mengerti cara mencegah dan merawat peserta gerak jalan yang ”hilang semangat” (collapse/flauwte), kejang (krampen), dan tersengat sinar matahari (zonnesteek)'),
(3, 1, 'Utama', 'a) telah memenuhi SKK Gerak Jalan Tingkat Madya, b) mengerti cara dan telah membiasakan diri untuk latihan berjalan kaki setiap hari, sekurang-kurangnya 2 km, c) mengerti cara dan telah melakukan ”langkah Pramuka” sejauh 2 km dalam waktu 14½ sampai 15½ menit, tanpa memperlihatkan nafas terengah-engah, sedikitnya dilakukan 2 kali, d) pernah mengikuti gerak jalan secara berkelompok atau perorangan sejauh 25 km untuk putra dan 15 km untuk putri, dan dilakukan sedikitnya 2 kali'),
(3, 2, 'Purwa', 'a) dapat mengingat 10 dari 15 macam benda yang dilihatnya dalam 1 menit (dilakukan dua kali percobaan dengan benda-benda yang berlainan), b) dapat mengenal dan mengingat sedikitnya 7 dari 10 macam benda yang dirabanya, dicium, dikecap dengan lidah, dan suara yang didengarnya, c) dapat mengikuti jejak sejauh 3 km, dengan menggunakan tanda jejak sederhana dari bahan alam sekitarnya, dan dapat mencatat sedikitnya 70% dari seluruh tanda yang dibuat penguji, d) (1) mengetahui dan mencatat cara dan kebiasaan hidup jenis binatang yang ada di sekitarnya, atau (2) mengetahui nama dan mengenal 10 macam tumbuh-tumbuhan/buah-buahan/ sayur-sayuran yang biasa digunakan manusia dan tumbuh di daerahnya, atau (3) mengetahui nama dan mengenal beberapa macam jamur (fungi) yang dapat dimakan atau yang beracun, yang tumbuh di daerahnya'),
(3, 2, 'Madya', 'a) telah memenuhi SKK Pengamat Tingkat Purwa, b) dapat mengingat sedikitnya 12 dari 18 benda yang dilihatnya dalam 1 menit, misalnya barang-barang dagangan di warung, macam-macam tanaman di kebun, dan sebagainya (dilakukan 2 kali percobaan dengan benda berlainan), c) dapat mengenal dan mengingat sedikitnya 9 dari 12 macam benda yang diraba, dicium, dikecap dengan lidah, dan suara yang didengarnya, d) dapat mengikuti jejak sejauh 5 km dengan menggunakan tanda jejak dan surat-surat penunjuk jalan, serta dapat mengingat kembali tiga di antara lima tempat penting yang dilewatinya, misalnya masjid/gereja, pasar, poliklinik, rumah sakit, dokter, dan lain-lain, e) bersama seorang kawan dapat membuat laporan/tertulis tentang sesuatu kejadian/peristiwa yang dilihatnya dan berlangsung kira-kira lima menit'),
(3, 2, 'Utama', 'a) telah memenuhi SKK Pengamat Tingkat Madya, b) dapat mengingat 15 dari 20 macam benda yang dilihatnya selama 1 menit, misalnya barang-barang di toko/pasar, makanan di meja pesta, peserta suatu rapat, Pramuka dalam latihan, dan sebagainya, c) dapat mengikuti jejak sejauh 5 km, dengan menggunakan peta, kompas, dan surat-surat penunjuk jalan; sesudah sampai di tempat terakhir dapat menunjukkan dalam peta itu letak dari (sedikitnya) 3 di antara 5 tempat penting yang dilewatinya, misalnya masjid/gereja, sekolah, rumah sakit/dokter, pasar, bengkel, dan sebagainya, d) telah mengamati sutau tempat/ruang, mendengar suara, meraba, mencium barang-barang dalam ruangan itu dalam waktu seluruhnya 5 menit, kemudian bersama dua orang kawan lainnya harus dapat melaporkan ”dugaan” tentang peristiwa yang terjadi di tempat itu, dan kira-kira 60% benar'),
(3, 3, 'Purwa', 'a) dapat memperlihatkan kecakapannya menyembunyikan diri atau menyamar secara sederhana, sehingga sukar dikenali orang (camouflage), b) mempunyai catatan/bukti bahwa ia telah: (1) mengetahui cara dan kebiasaan hidup dari satu jenis/macam binatang, atau (2) mengenal sedikitnya 2 macam tumbuh-tumbuhan, dan lain-lain, baik yang berguna maupun yang merusak/beracun bagi manusia/hewan, atau (3) mengenal 2 macam jamur yang dapat dimakan orang atau yang beracun dan tahu bahaya, pencegahan dan pengobatan atas keracunan itu, c) dapat mengenali dua orang teman/pembina/pengujinya yang menyamar di tengah orang banyak, dan dapat memberikan laporan tentang keadaan dan kegiatan yang dilakukan orang itu selama lebih kurang 10 menit yang dilihatnya dari jarak tertentu, d) dapat memperlihatkan kecakapannya mengikuti (membayangi), merunduk, atau merayap (dengan salah satu gaya merayap sesuai dengan tempatnya), melalui jarak lebih kurang 300 meter, mendekati penguji/orang lain di tempat tertentu secara diam-diam, tanpa terlihat dan terdengar'),
(3, 3, 'Madya', 'a) telah memenuhi SKK Pengamat Tingkat Purwa, b) dapat memperlihatkan kecakapannya menyamar sesuai dengan tempatnya, dengan mempergunakan benda-benda/bayangan-bayangan untuk tempat persembunyiannya, c) (1) dapat mendekati dan mengikuti (membayangi) penguji atau orang lain di tempat tertentu, - dengan berbagai cara menurut keadaan setempat, - dimulai dari jarak lebih kurang 500 meter sampai dekat tanpa diketahui atau disadari penguji/orang lain tersebut, - dilakukan pada siang hari, - melintasi jalan raya dan gang/lorong-lorong, serta bangunan-bangunan dan tanah lapang, - bila mungkin dengan cuaca yang berlainan (panas, hujan, kabut, dan lain-lain), - dan melaporkan keadaan atau kegiatan orang yang diikuti/ dibayanginya, atau (2) dapat merunduk atau merayap mendekati penguji/orang lain di tempat tertentu: - dilakukan dengan berbagai cara menurut keadaan setempat, - melintasi jarak 500 meter sampai dekat dengan penguji/ orang lain tersebut dengan tanpa dilihat dan didengar oleh penguji/orang lain tersebut, - dilakukan pada siang hari, - melalui tanah lapang, bukit, daerah dengan pohon-pohon/ batu-batu/bangunan-bangunan, - dengan bermacam-macam latar belakang (back-ground), misalnya langit terang, gunung, kebun, atau hutan, - dan melaporkan keadaan atau kegiatan orang yang diintai itu, d) (1) telah membuat catatan hasil pengamatannya atas empat jenis tanaman, termasuk pembuatan herbarium atau gambar sketsa atau foto tentang bagian tanaman itu, atau (2) telah membuat catatan hasil pengamatannya atas 4 jenis binatang, termasuk pembuatan gambar sketsa atau foto tentang kehidupan binatang itu'),
(3, 3, 'Utama', 'a) telah memenuhi SKK Penyelidik Tingkat Madya, b) dapat memperlihatkan kecakapannya menyamar dengan memperlihatkan adanya angin, air sungai/kolam, pohon/batu/ bangunan, cahaya terang, bayang-bayang dan sebagainya, dan dapat membekukan dirinya dalam 2 menit (tetap bernafas) serta melakukan gerakan perlahan-lahan sekali (gerak meleleh es), sehingga sukar dikenal orang, c) sama dengan syarat nomor c) (1) dan (2) pada SKK Penyelidik Tingkat Madya di atas, tetapi dilakukan pada malam hari, dengan keringanan-keringanan sesuai dengan keadaan tempat, cuaca, dan suasana malam hari, d) telah membuat catatan hasil pengamatannya atas sedikitnya dua jenis tanaman atau binatang liar (yang tidak biasa dipelihara manusia), termasuk pembuatan herbarium atau gambar sketsa atau foto tentang bagian tanaman atau kehidupan binatang itu'),
(3, 4, 'Purwa', 'a) berenang sejauh 15 meter, dengan berpakaian seragam, dan melepaskan pakaiannya dalam air (dengan kaki tanpa menyentuh dasar), b) berenang gaya punggung sejauh 20 meter, gaya katak sejauh 20 meter, gaya samping/gaya bebas sejauh 20 meter, secara berturut-turut sehingga jarak yang ditempuh berjumlah 60 meter, c) menyelam dalam air, dan mengambil benda di dasar sedalam tidak lebih dari 2 meter, d) terjun dengan baik dari tepi kolam renang'),
(3, 4, 'Madya', 'a) telah memenuhi SKK Perenang Tingkat Purwa, b) berenang sejauh 20 meter dengan pakaian seragam, serta melepaskan pakaiannya dalam air, dengan kaki tanpa mengenai dasar, c) mengapung di atas punggung atau dengan gerakan tangan/kaki, selama sedikitnya 40 detik dalam air tawar atau 45 detik dalam air asin, d) berenang dengan gaya punggung sejauh 25 meter, gaya katak sejauh 25 meter, dan gaya bebas sejauh 25 meter, secara berturut-turut, sehingga jarak tempuh seluruhnya berjumlah 75 meter, atau jarak itu ditempuh dengan satu macam gaya saja, e) menyelam dan mengambil benda di dasar kolam renang sedalam 3 meter'),
(3, 4, 'Utama', 'a) telah memenuhi SKK Perenang Tingkat Madya, b) berenang dengan gaya punggung sejauh 50 meter, gaya katak sejauh 50 meter, dan gaya bebas sejauh 50 meter, secara berturut-turut, sehingga jarak tempuh seluruhnya berjumlah 150 meter, atau jarak itu ditempuh dengan satu macam gaya saja, c) berenang menyelam selama 60 detik, dengan kaki tanpa mengenai dasar, d) berenang mengapung selama 3 menit di air tawar atau 5 menit di air asin, dengan kaki tanpa mengenai dasar, e) berenang sejauh 200 meter, dengan beberapa macam gaya menurut pilihannya, f) terjun lomba dari tepian dan loncat dari papan loncat setinggi 3 meter dengan beberapa cara'),
(3, 5, 'Purwa', 'a) dapat berenang dan menggunakan alat-alat keselamatan, b) memahami bagian-bagian perahu dan bagian-bagian layar dan dengan aktif dapat memasang sendiri setiap bagian perahu dan layar yang siap untuk berlayar, c) memahami cara perawatan ringan dari perahu dan layar, misalnya membersihkan dari minyak, menjemur layar, dan sejenisnya, d) dapat mendayung sehingga perahu bergerak dengan terkemudi/ terarah dengan tepat, dan memahami tali-temali, e) dapat mengemudikan perahu dengan baik, f) memahami arah angin, dan dapat menceritakan bagaimana kapal itu dapat berlayar dengan angin-angin tertentu, g) memahami tanda-tanda pelayaran yang ringan atau banyak dikenal'),
(3, 5, 'Madya', 'a) telah memenuhi SKK Juru Layar Tingkat Purwa, b) telah mengikuti dengan aktif latihan-latihan layar, c) memahami navigasi ringan, dan dapat menggunakan alat-alat navigasi yang sederhana, misalnya kompas, stopwatch, baringan, dan sejenisnya, d) memahami setiap lalu-lintas pelayaran rakyat yang berada di daerahnya masing-masing, dan dapat menceritakan dengan jelas, e) menguasai perbaikan perahu/layar, misalnya akal, mengorek tiram, menjahit layar, dan sejenisnya'),
(3, 5, 'Utama', 'a) telah memenuhi SKK Juru Layar Tingkat Madya, b) aktif dalam misi-misi pelayaran daerah yang membaktikan diri untuk angkutan masyarakat setempat, c) dapat menggambarkan batas-batas wilayah cabangnya, bidang-bidang lautnya, dan mengetahui dengan baik, d) dapat membaca peta, mengetahui waktu-waktu perubahan angin di daerahnya, termasuk masa-masa pasang-surut, e) memahami peraturan olahraga layar nasional/Peropi dan dapat melaksanakan dengan baik, f) mempunyai dua karya untuk TKK Juru Layar, g) membuat kertas kerja mengenai pelayaran di Indonesia, mengenai jalur lalu-lintas ekonomi, dengan muatannya untuk seluruh Indonesia, yang menuju ke daerah masing-masing termasuk kapal bukan layar Indonesia/asing'),
(3, 6, 'Purwa', 'a) mempunyai kondisi badan/kesehatan yang baik (keterangan dokter), b) pandai berenang dengan sedikitnya salah satu gaya renang, c) tahan menyelam tanpa mempergunakan bantuan peralatan selama 45 detik, d) dapat mempergunakan alat snorkel (yang digunakan di mulut) untuk berenang sejauh 50 meter, e) tahan masuk ruang tekan dengan tekanan 1 atmosfer'),
(3, 6, 'Madya', 'a) telah memenuhi SKK Juru Selam Tingkat Purwa, b) masih mempunyai konsidi badan/kesehatan yang baik (surat keterangan dokter), c) pandai berenang sedikitnya dua macam gaya renang, d) tahan menyelam tanpa bantuan alat, selama 1½ menit, e) tahan berenang dengan menggunakan snorkel dengan jarak 100 meter, f) tahan masuk ruangan tekan dengan tekanan 1½ atmosfer, g) dapat menggunakan alat selam ringan termasuk: (1) akualung, (2) isam, (3) dan alat lain yang masih termasuk alat selam ringan, h) dapat menyelam dalam air laut sedalam 10 meter'),
(3, 6, 'Utama', 'a) telah memenuhi SKK Juru Selam Tingkat Madya, b) masih mempunyai kondisi badan/kesehatan yang baik, c) tahan menyelam dalam waktu dua menit tanpa menggunakan alat, d) mahir menyelam dengan segala alat selam ringan: - alat selam sekulatir terbuka (akualung), - alat selam sekulatir terbuka (akualung), - alat selam sekulatir tertutup, - dapat menyelam sedalam 20 meter dalam air laut, e) tahan masuk ruangan tekan dengan tekanan 2 atmosfer, f) dapat menyelam dengan alat selam berat (klomik) sehingga mencapai kedalaman 12 meter dalam air laut'),
(3, 7, 'Purwa', 'a) dapat berenang dan menggunakan pelampung, b) menguasai teknik mendayung dan mengemudikan perahu/ sampan, c) memahami setiap gerak dari mulai perahu di darat sampai berada di air, siap untuk bergerak, d) dapat mendekatkan/merapatkan perahu ke kapal, atau berlabuh dengan baik, e) memahami simpul-simpul tali-temali dengan baik dan dapat menggunakannya untuk menghela perahu, serta menambatkan perahu dan kapal di tepian'),
(3, 7, 'Madya', 'a) telah memenuhi SKK Pendayung Tingkat Purwa, b) dapat menggerakkan perahu dengan memperhitungkan arah arus dan angin, c) dapat menggunakan jangkar untuk menolong sesuatu/diri sendiri, d) tahu cara dan dapat memberi muatan perahu (barang atau orang), e) memahami setiap bahaya dari benturan/gesekan dengan karang, baik dari tanda-tanda/bendera-bendera yang dipasang maupun yang tidak dipasang'),
(3, 7, 'Utama', 'a) telah memenuhi SKK Pendayung Tingkat Madya, b) memahami perlengkapan perahu/alat-alat penolong, perawatan/ perbaikan dan penggunaannya, terutama bila sewaktu-waktu timbul bahaya, c) tahu syarat-syarat keamanan/pelanggaran pelayaran (aanvarings reglement), d) memahami teknik mendayung perahu, sampan, sekoci, kano, dengan aba-abanya, e) dapat memimpin beberapa Pramuka untuk mendayung sampan/ perahu, dan memberikan penghormatan dengan dayung perahu, f) tahu peraturan-peraturan pertandingan dan staf kerjanya (misalnya juri), sampai memasang rambu/lintasan/sertifikat dari Peropi, g) mendalami kualitas perahu (yang ada di Indonesia/luar negeri), misalnya perahu terbuat dari kayu jati, fiberglass, dan sejenisnya sehingga dapat mengetahui cara perawatannya dengan baik'),
(3, 8, 'Purwa', 'a) mengenal alat-alat dan perlengkapan ski air, b) mengenal out boat yang digunakan untuk ski air (tipenya), c) dapat dan mengetahui cara main ski dengan berdiri pada kedua belah kakiknya'),
(3, 8, 'Madya', 'a) telah memenuhi SKK Ski Air Tingkat Purwa, b) mengetahui alat-alat perlengkapan tipe out boat dan kekuatan mesinnya, c) mengetahui cara dan dapat mengolah gerak out boat dengan baik, d) dapat membuat keseimbangan badan waktu bermain ski air dengan satu kaki diangkat'),
(3, 8, 'Utama', 'a) telah memenuhi SKK Ski Air Tingkat Madya, b) telah memelihara dengan baik alat-alat ski air, dan motor out boatnya c) selain dapat bermain ski air, juga dapat mengolah gerak out boat untuk menarik pemain ski air, d) dapat memparagakan semua gerak permainan ski air, e) selalu berlatih dengan baik dan selalu berusaha meningkatkan prestasinya'),
(4, 1, 'Purwa', 'a) membuat sedikitnya 10 batang stek dan menanamnya menurut ketentuan yang diperlukan usaha peternakan ulat sutera sampai menjadi pohon besaran yang berumur 3 bulan, b) memelihara sedikitnya 200 ulat sutera dari saat menetas keluar dari telur sampai waktu membuat kokon dan menjadi kepompong, c) dapat menyeleksi kokon dan mengkonservasi kokon-kokon sehingga tahan disimpan lama'),
(4, 1, 'Madya', 'a) telah memenuhi SKK Peternak Ulat Sutera Tingkat Purwa, b) dapat memangkas pohon-pohon besaran dalam rangka usaha peternakan ulat sutera, c) melaksanakan ketentuan tentang kebersihan dan kesehatan yang diperlukan untuk peternakan ulat sutera, d) dapat memintal kokon dengan alat pemintalan tangan sampai menjadi streng benang sutera yang siap untuk dijual'),
(4, 1, 'Utama', 'a) telah memenuhi SKK Peternak Ulat Sutera Tingkat Madya, b) dapat memelihara kepompong sampai menjadi kupu-kupu, mengawinkannya sampai bertelur, dan memelihara telurnya sampai menetas keluar dari telur sampai waktu membuat kepompong, c) membuat alat-alat pemeliharaan ulat sutera, dari waktu menetas keluar dari telur sampai waktu membuat kokon, d) dapat menyelenggarakan suatu usaha pertenakan ulat sutera disertai pembukuan teknis dan komersial seperlunya'),
(4, 2, 'Purwa', 'a) dapat membuat kandang kelinci yang sederhana, tetapi kuat dan sesuai untuk peternakan kelinci, b) dapat memelihara sedikitnya 4 ekor kelinci betina, c) dapat mengawinkan dan memelihara sedikitnya seekor kelinci betina sampai melahirkan dan menyusui anaknya hingga mencapai umur 2 bulan'),
(4, 2, 'Madya', 'a) telah memenuhi SKK Peternak Kelinci Tingkat Purwa, b) dapat melaksanakan ketentuan tentang kebersihan dan kesehatan yang diperlukan untuk peternakan kelinci, c) dapat menyembelih, menguliti dan memasak kelinci'),
(4, 2, 'Utama', 'a) telah memenuhi SKK Peternak Kelinci Tingkat Madya, b) dapat melaksanakan ketentuan tentang kebersihan dan kesehatan yang diperlukan untuk peternakan kelinci, c) dapat menyembelih, menguliti dan memasak kelinci'),
(4, 3, 'Purwa', 'a) dapat mengenal isi sarang dan tata cara kehidupan lebah madu, b) tahu cara dan dapat membuat kotak lebah madu, c) tahu cara memindahkan keluarga lebah madu dari gelodog/satu tempat lain ke dalam kotak lebah madu, d) dapat mengenal manfaat lebah madu bagi produksi pertanian'),
(4, 3, 'Madya', 'a) telah memenuhi SKK Peternak Lebah Tingkat Purwa, b) tahu cara dan dapat membersihkan kotak lebah madu, c) tahu cara dan dapat menggunakan berbagai alat peternakan lebah madu, d) tahu cara dan dapat mengambil madu dari sarang lebah madu, e) telah memelihara satu keluarga lebah madu sedikitnya selama 6 bulan, f) dapat menerangkan faktor-faktor penting yang dapat mempengaruhi hasil produksi lebah madu'),
(4, 3, 'Utama', 'a) telah memenuhi SKK Peternak Lebah Tingkat Madya, b) tahu cara dan dapat mengirim paket lebah dan ratu lebah, c) tahu cara dan dapat menternakkan ratu lebah madu, d) dapat menyelenggarakan suatu usaha peternakan lebah madu, disertai pembukuan teknis dan komersial seperlunya'),
(4, 4, 'Purwa', 'a) mengenal sedikitnya 5 jenis tanaman hias, 5 jenis tanaman buah-buahan, dan 5 jenis tanaman sayur-sayuran, b) dapat membuat dan mempergunakan pupuk kompos, c) mengenal sedikitnya 3 macam hama dan penyakit tanaman dan tahu cara pencegahan dan pemberantasannya, d) telah memelihara sedikitnya satu jenis tanaman hias, satu jenis tanaman buah-buahan, atau satu jenis tanaman sayur-sayuran sampai berbunga, sampai berbuah, sampai dipanen, atau sedikitnya selama 3 bulan'),
(4, 4, 'Madya', 'a) telah memenuhi SKK Juru Kebun Tingkat Purwa, b) mengenal berbagai macam obat pencegah dan pemberantas hama, dan dapat menggunakannya, c) mengenal berbagai macam pupuk dan dapat menggunakannya, d) dapat menyemaikan, mencangkok, dan mengokulasi tanaman, e) dapat memangkas tanaman supaya menghasilkan buah lebih banyak'),
(4, 4, 'Utama', 'a) telah memenuhi SKK Juru Kebun Tingkat Madya, b) tahu arti dan pentingnya bibit unggul, dan tahu di mana dapat memperolehnya, c) tahu cara untuk memperoleh kredit untuk produksi pertanian, d) dapat menyelenggarakan sekedar usaha perkebunan, disertai pembukuan teknis dan komersial seperlunya'),
(4, 5, 'Purwa', 'a) telah memenuhi SKK Penenun untuk Siaga, b) dapat mengkelos dan mempalet, c) menenun dengan ATBM sedikitnya 1 orang dengan benang-benang yang berwarna-warni'),
(4, 5, 'Madya', 'a) telah memenuhi SKK Penenun Tingkat Purwa, b) dapat mencucuk, c) dapat mencelup benang tenun dengan berbagai warna, d) dapat menenun dengan ATBM kain yang bercorak sedikitnya 6 meter'),
(4, 5, 'Utama', 'a) telah memenuhi SKK Penenun Tingkat Madya, b) dapat memetani dan mem-boom, c) dapat menenun dengan ATBM yang ditambah dengan dobi sehingga menghasilkan kain ”kruisweiving” sedikitnya 6 meter, d) dapat mencelup dan memberi warna pada kain blaco, e) telah memiliki sebuah ATBM, dapat memelihara dan memperbaiki kerusakan-kerusakannya, f) dapat menyelenggarakan suatu usaha pertenunan tangan disertai pembukuan teknis dan komersial seperlunya'),
(4, 6, 'Purwa', 'a) dapat mengenal tiga macam bambu, sifat-sifat dan pemakaiannya, b) dapat mengasah, memelihara dan menggunakan alat-alat yang biasa dipakai untuk menebang, membersihkan dan mengerjakan bambu, c) dapat membuat pelupuh, saluran air, tali bambu, dan barang-barang hasta karya sederhana dari bambu'),
(4, 6, 'Madya', 'a) telah memenuhi SKK Juru Bambu Tingkat Purwa, b) tahu dan dapat mengenal 5 macam bambu, sifat-sifat dan penggunannya, c) dapat membuat sambungan-sambungan bambu untuk mendirikan bangunan, misalnya: (1) sambungan memanjang (2) sambungan bersilang (3) sambungan huruf T dengan penguat miring (dengan pasak dan lubang), d) dapat membuat hasta karya bambu, memasang dinding, pintu, timba sumur (sengot, Jawa), untuk pagar, membuat alat-alat perkemahan sederhana: rak, dapur, menara semboyan (seintoren) dan sebagainya'),
(4, 6, 'Utama', 'a) telah memenuhi SKK Juru Bambu Tingkat Madya, b) dapat membuat sambungan-sambungan bambu untuk mendirikan bangunan, misalnya: (1) sambungan berbentuk sudut miring (tidak siku-siku), (2) sambungan 3 batang bambu yang masing-masing membuat sudut siku-siku dengan penguat miring (pasak dan lubang), (3) sambungan kait untuk ujung hubungan, (4) tahu bagaimana cara memasang bambu yang dikerjakan untuk bangunan, sehingga tidak patah dan tahu sebab-sebabnya; c) dapat membuat barang-barang dari bambu, misalnya: bilik/gedek, kursi bambu, hiasan-hiasan bambu, dan sebagainya yang sedapat mungkin membuat kreasi sendiri, d) dapat merencanakan dan membuat alat-alat perkemahan dari bambu, misalnya: gapura (pintu gerbang), meja perkemahan, gubug pejagaan, dan sebagainya'),
(4, 7, 'Purwa', 'a) tahu tempat diperolehnya bahan anyaman dan dapat menyiapkan untuk dikerjakan, b) dapat membuat sedikitnya lima macam barang anyaman sederhana, dari bahan seperti janur, jerami, kertas, rumput, pandan, dan sebagainya, untuk bermacam-macam kerajinan, seperti: slongsong ketupat, keranjang, tikar, bleketepe, kipas, keranjang (untuk bawa) ayam, dan sebagainya, c) dapat memperlihatkan hasil anyamannya'),
(4, 7, 'Madya', 'a) telah memenuhi SKK Juru Anyam Tingkat Purwa, b) dapat membuat sedikitnya 7 macam barang anyaman, baik yang sederhana, maupun yang sulit, misalnya, tikar yang ditenun/lampit, besek, tas, anyaman kurai, dan sebagainya dari bahan alam atau tiruan, misalnya dari plastik, rafia, dan sebagainya, c) dapat memperlihatkan hasil anyaman yang diberi hiasan, sehingga memungkinkan untuk dijual'),
(4, 7, 'Utama', 'a) telah memenuhi SKK Juru Anyam Tingkat Madya, b) dapat membuat barang anyaman halus, misaalnya, kursi rotan, kereta anak, keranjang bayi, kap lampu, tudung saji, dan sebagainya, dari bahan bambu, rotan (pitrit atau kulit), plastik, rami, dan sebagainya, c) dapat menunjukkan hasil karya yang dapat dijual'),
(4, 8, 'Purwa', 'a) tahu dan dapat menggunakan alat-alat tukang kayu, misalnya gergaji, palu, catut, paku, sekerup, bor, pahat (beitel) dan ketam (serut), b) dapat membuat alat rumah tangga sederhana dari kayu lunak, misalnya rak handuk, dingklik (tempat duduk jongkok), bingkai gambar, bak sampah, kotak surat, dan sebagainya, c) dapat menggunakan paku atau sekerup sedalam 1½” pada kayu setebal ½” tanpa merusak kayu, paku atau sekerupnya, d) mengenal macam, sifat, kualitas dan penggunaan kayu yang ada di daerahnya'),
(4, 8, 'Madya', 'a) telah memenuhi SKK Juru Kayu Tingkat Purwa, b) dapat memelihara alat-alat tukang kayu, mengasah pahat, ketam dan gergaji, c) tahu dan dapat menggunakan sambungan-sambungan papan melebar (takikan separuh atau laki-bini), sambungan ekor burung, dan sambungan purus lubang, dalam pembuatan barang-barang, misalnya papan tulis, kursi/dingklik panjang dan lain-lain, d) tahu dan dapat menggunakan dempul (lilin penutup lubang) cat, dan perekat (lem) kayu, e) dapat membaca gambar rencana pekerjaan dan tahu ukuran-ukuran kayu dan penggunaannya. f) telah melatih sedikitnya seorang Pramuka lain mencapai TKK Juru Kayu Tingkat Purwa'),
(4, 8, 'Utama', 'a) telah memenuhi SKK Juru Kayu Tingkat Madya, b) dapat membuat lekuk (sponing) untuk memasang panel/kaca/ hardboard pada bingkainya, c) dapat membuat sketsa rencana pekerjaan kayu, dengan ukuran-ukurannya, d) tahu dan dapat membuat barang-barang/bagian bangunan dengan sambungan-sambungan kayu, e) dapat menggunakan vernis, pelitur dengan baik dan tahu cara pemeliharaan barang-barang yang dipelitur'),
(4, 9, 'Purwa', 'a) tahu cara dan dapat menyusun lapisan-lapisan bata merah untuk tembok setengah bata dan satu bata, dengan beberapa macam/ variasi susunan, di: (1) bagian ujung/tengah tembok, (2) pertemuan dua tembok bersudut siku-siku, (3) pertemuan tiga tembok berbentuk huruf T, (4) pertemuan silang (empat tembok masing-masing bersudut siku-siku), (5) perkuatan di tempat-tempat tersebut di atas; b) tahu perbandingan bahan-bahan dan dapat membuat adukan mortel untuk macam-macam keperluan, c) tahu dan dapat dapat menggunakan alat-alat tukang batu seperti mistar, penyiku, batu duga (schietlood), waterpas, serok/sendok tukang batu, dan sebagainya, d) dapat membaca gambar rencana bangunan'),
(4, 9, 'Madya', 'a) telah memenuhi SKK Juru Batu Tingkat Purwa, b) tahu cara dan dapat menyusun lapisan bata merah untuk setengah dan satu bata, di bagian tembok melengkung misalnya tembok sumur/perigi, bagian atas pintu dengan/tanpa lengkung dan sebagainya, c) dapat memasang pondasi rumah biasa, dan menempatkan gawang pintu/jendela (kusen) di tempatnya, d) dapat membuat lantai plester semen'),
(4, 9, 'Utama', 'a) telah memenuhi SKK Juru Batu Tingkat Madya, b) tahu cara dan dapat menyusun lapisan bata merah/batu kali untuk tembok satu setengah bata, atau lebih untuk bermacam-macam keperluan, misalnya dinding, pilar, bak/kolam air, dan sebagainya, c) dapat membuat skesa rencana pondasi, atau bagian bangunan lain yang berhubungan dengan tukang batu, dengan memberi ukuran-ukuran pokoknya, d) tahu cara dan dapat memasang lantai tegel, atau batu hiasan (klai, granit, dan sebagainya) di dinding tembok'),
(4, 10, 'Purwa', 'a) tahu cara dan dapat membersihkan dan memelihara alat-alat dari logam, misalnya barang-barang dari tembaga, kuningan perak, kaleng dan sebagainya, b) dapat memperbaiki kerusakan-kerusakan kecil pada barang-barang dari kaleng, c) dapat memelihara dan menggunakan alat-alat ringan untuk logam, misalnya gunting seng, palu, tang, solder, dan sebagainya, d) dapat menggunakan barang bekas dari logam untuk membuat mainan, peralatan rumahtangga, dan sebagainya, misalnya membuat lampu minyak, pigura, cermin, dan sebagainya'),
(4, 10, 'Madya', 'a) telah memenuhi SKK Juru Logam Tingkat Purwa, b) dapat membuat barang sederhana dari bahan seng, alumunium, perak, tembaga, atau sebagainya, yang diperlukan dalam rumah tangga, misalnya serok, kukur kelapa (parut, Jawa), lampu ting, sendok, dan sebagainya, c) dapat menggunakan kikir, tatah, jangka, alat untuk penghalus dan pembuat kilap (glasur), bubut, alat tempa, dan sebagainya'),
(4, 10, 'Utama', 'a) telah memenuhi SKK Juru Logam Tingkat Madya, b) mengetahui campuran dan sifat benda dari logam solder dan logam tuang, c) tahu dan dapat melaksanakan salah satu dari pekerjaan sebagai berikut: (1) mencairkan logam (2) membuat barang tuangan (3) membuat barang yang ditempa (4) membuat barang yang dibubut, (5) dan lain-lain, d) dapat membuat rencana gambar benda atau hiasan pada benda logam, dan sebagainya'),
(4, 11, 'Purwa', 'a) tahu jenis, tanda, kualitas dan penggunaan berbagai macam kulit, dan tahu cara, bahan, dan dapat memelihara barang-barang dari kulit, b) (1) dapat mengerjakan pekerjaan-pekerjaan ringan, misalnya menggunting kulit sesuai dengan pola, membuat lubang, membuat tali/string, merekat kulit, dan sebagainya, atau, 2) dapat membuat barang-barang sederhana dari kulit kelinci, kulit marmut, kulit kambing, kulit sapi, atau hewan lain, misalnya membuat pici, dompet, tas, dan sebagainya, c) tahu cara dan dapat memelihara dan menggunakan beberapa alat tukang kulit'),
(4, 11, 'Madya', 'a) telah memenuhi SKK Juru Kulit Tingkat Purwa, b) tahu cara menguliti hewan, mengerjakan secara sederhana supaya kulitnya dapat dimanfaatkan, dan tahu kerusakan kulit akibat kesalahan mengerjakannya, c) (1) dapat menggunakan dan mememlihara alat-alat untuk membuat gambar hiasan pada kulit, misalnya pahat, alat pelubang, holder, penghapus, stempel, cat, dan sebagainya, atau, (2) dapat memperbaiki kerusakan barang dari kulit, misalnya menjahit tas sobek, memperbaiki sol/hak sepatu, dan sebagainya'),
(4, 11, 'Utama', 'a) telah memenuhi SKK Juru Kulit Tingkat Madya, b) telah mempelajari dan mempraktekkan cara menyamak, mengobati dan mengerjakan kulit, sehingga dapat digunakan untuk membuat barang-barang kulit, c) dapat membuat barang-barang dari kulit sapi, kerbau, kambing dan sebagainya, misalnya tas, sepatu, dan sebagainya, dengan menggunakan berbagai macam alat, d) mempunyai catatan tentang kemajuan usahanya mencari penghasilan dengan hasil karya Juru Kulit'),
(4, 12, 'Purwa', 'a) tahu nama dan mengenal berbagai jenis kertas dan bahan untuk menjilid buku, seperti kertas HVS, doorslag, HVS, karton manila, linen, pualam, jenis lem, dan sebagainya, b) dapat membuat album foto, album perangko, atau notes/ bloknote, c) dapat menyusun lembaran-lembaran kertas menjadi satu berkas (bendel), dengan memperhatikan urutan halaman dan sisi yang akan dipotong, membuat kulit luar dari karton manila, memasang kertas penumpu dan menjilidnya menjadi berkas terjilid'),
(4, 12, 'Madya', 'a) telah memenuhi SKK Penjilid Buku Tingkat Purwa, b) dapat menyusun beberapa buah buku tulis atau majalah atau lainnya semacam itu dengan memperhatikan nomor dan urutan halaman, serta sisi yang akan dipotong, memasang pita dengan jahitan, membuat kulit luar dari karton dan kertas marmer, memasang lembaran, memasang sudut linen, dan menggabungkannya menjadi sebuah berkas, c) mengerti cara menyimpan buku agar tidak rusak karena cuaca atau binatang'),
(4, 12, 'Utama', 'a) telah memenuhi SKK Penjilid Buku Tingkat Madya, b) dapat menyusun berkas-berkas dan menjilidnya menjadi buku tebal, seperti kamus, ensiklopedi, dan sebagainya, dengan menggunakan kain strimien, kertas linen, balok pembentuk punggung buku, dan sebagainya, c) dapat membuat tulisan, monogram dan sebagainya, secara timbul di kulit luar buku, dan pada bundel menjilid surat kabar, atau selebaran semacam itu, d) dapat memperbaiki buku-buku yang rusak jahitan/jilidnya'),
(4, 13, 'Purwa', 'a) dapat memelihara alat fotografi, dan tahu merek, ASA/DIN, masa laku dan penggunaan beberapa jenis film, b) dapat menggunakan alat fotografi, dan tahu cara kerja bagian-bagiannya, misalnya penggunaan diafrahma sesuai dengan cuaca, pengatur jarak, dan sebagainya, c) telah memotret dengan tustel film, dan berhasil baik benda tak bergerak, misalnya pemandangan alam, keadaan perkemahan, bangunan monumen, dan sebagainya, masing-masing 3 buah'),
(4, 13, 'Madya', 'a) telah memenuhi SKK Juru Potret Tingkat Purwa, b) dapat menggunakan alat fotografi dengan lampu kilat (blitz), c) dapat menggunakan tustel untuk memotret berbagai macam keadaan dalam ruangan (indoor), alam di luar (outdoor) siang dan malam, foto bersama orang banyak (grup foto) dan sebagainya, masing-masing sedikitnya 3 buah dengan hasil baik, d) dapat menyusun dan menyiapkan dengan baik foto-foto dan film negatifnya'),
(4, 13, 'Utama', 'a) telah memenuhi SKK Juru Potret Tingkat Madya, b) dapat menggunakan alat fotografi dengan lensa tele, dan film untuk slide, c) dapat memotret obyek yang bergerak, binatang, pemandangan di danau/laut, dan permainan awan (wolkensel), orang tanpa disadari yang bersangkutan, masing-masing sedikitnya 3 buah, d) dapat menjelaskan kebaikan dan kekurangan karyanya, akibat pengaturan diafrahma, cahaya, kecepatan, kesalahan mencuci atau mencetak (afdruk), pemilihan jenis film, komposisi, dan sebagainya'),
(4, 14, 'Purwa', 'a) dapat mempergunakan 2 macam alat penangkap ikan, tahu ukuran-ukuran dan gunanya, b) mempunyai pengetahuan tentang berbagai jenis ikan yang hidup di daerahnya, dan mengetahui umpan serta alat untuk menangkapnya, c) dapat membuat salah satu alat penangkap ikan, pelampung, serangga buatan, d) dapat memperlihatkan hasil usahanya menangkap ikan, membersihkan dan memasaknya'),
(4, 14, 'Madya', 'a) telah memenuhi SKK Juru Penangkap Ikan Tingkat Purwa, b) tahu dan dapat mempergunakan beberapa macam alat penangkap ikan, c) tahu peraturan dan etika menangkap ikan, tahu waktunya dan besarnya ikan yang ditangkap, d) tahu dan dapat memperbaiki kerusakan kecil pada alat penangkap ikan, misalnya joran yang patah, tali kail putus, jala yang koyak, mengasah mata kail, dan sebagainya, dan dapat menggunakan simpul-simpul yang berkaitan dengan itu, e) mempunyai catatan tentang pengalamannya menangkap ikan, misalnya cuaca, jenis dan berat ikan, dan hasil penangkapannya selama satu musim (lk. 3 bulan)'),
(4, 14, 'Utama', 'a) telah memenuhi SKK Penangkap Ikan Tingkat Madya, b) mengetahui perairan di sekitar rumahnya dalam radius 25 km, c) tahu dan telah ikut serta dalam penangkapan ikan laut dengan salah satu cara menangkap ikan, misalnya dengan jaring seret, jaring biasa, jala, dan sebagainya dan penangkapan tiram, d) dapat menerangkan bentuk, guna dan cara memakai jaring biasa, jaring seret, serta memperbaiki kerusakan-kerusakan kecil, e) tahu tempat berbahaya, tanda akan ada badai, hujan, ombak besar, dan sebagainya, cara menghindarkan diri dari bahaya, dan tanda-tanda minta pertolongan'),
(4, 15, 'Purwa', 'a) talah memelihara itik sebanyak lebih dari 10 ekor, selama sedikitnya 3 bulan, b) dapat memperlihatkan usahanya memelihara kandang, membersihkan dan mencegah kemungkinan adanya penyakit dan gangguan lain, c) dapat membuat ramuan makanan, dan mengatur waktu pemberian makanan atau minuman, d) dapat menggembalakan itik, dan tahu waktu dan tempat bertelurnya'),
(4, 15, 'Madya', 'a) telah memenuhi SKK Peternak Itik/Mentok/Angsa Tingkat Purwa, b) telah memelihara itik sebanyak 20 ekor atau lebih selama sedikitnya 6 bulan, c) mengerti dan dapat menjelaskan manfaat daging dan telur itik untuk kesehatan manusia, d) dapat menjelaskan tanda-tanda, sifat kelemahan itik, penyakit dan pengobatannya. e) tahu cara dan dapat memilih telur, dan menetaskannya dengan induk ayam atau alat penetas telur'),
(4, 15, 'Utama', 'a) telah memenuhi SKK Peternak Itik/Mentok/Angsa Tingkat Madya, b) tahu cara dan memelihara itik dari umur sehari sampai umur 3 bulan, c) tahu cara dan telah membuat telur asin dengan baik, d) mempunyai catatan tentang perkembangan dari itk-itiknya, produksinya, kemajuan dan keuntungan yang diperoleh, dari pemeliharaan itik'),
(4, 16, 'Purwa', 'a) telah memelihara ayam sebanyak lebih dari 10 ekor, selama sedikitnya 3 bulan, b) mengerti dan dapat membuat ramuan makanan ayam (termasuk untuk anak ayam dan ayam yang sedang bertelur) serta dapat mengatur waktu pemberian makan/minum, c) tahu dan dapat memelihara kandang, membersihkan dan mencegah kemungkinan serangan penyakit/gangguan terhadap ayam, d) mengerti dan dapat menjelaskan manfaat daging dan telur ayam untuk kesehatan manusia dan dapat memilih serta menyimpan telur'),
(4, 16, 'Madya', 'a) telah memenuhi SKK Peternak Ayam Tingkat Purwa, b) telah memelihara ayam sebanjak 15 ekor atau lebih selama sedikitnya 6 bulan, c) mengerti dan dapat menjelaskan tanda-tanda, sifat, kelemahan dan kebaikan dari beberapa jenis/ras ayam, d) tahu dan dapat mengeramkan telur dengan induk ayam atau dengan alat penetas telur'),
(4, 16, 'Utama', 'a) telah memenuhi SKK Peternak Ayam Tingkat Madya, b) tahu cara dan telah memelihara ayam dari umur sehari sampai umur 3 bulan atau lebih, sedikitnya 20 ekor, c) tahu tanda-tanda, cara pencegahan, penyuntikan dan pengobatan beberapa jenis penyakit ayam, d) mempunyai catatan tentang perkembangan dari ayam-ayamnya, pengobatan dan produksinya, serta dapat memperlihatkan kemajuan atau hubungan dari usaha peternakan ayamnya'),
(4, 17, 'Purwa', 'a) telah memelihara selama sedikitnya 3 bulan, salah satu jenis ternak sebagai berikut: (1) kambing/domba/babi sebanyak 4 ekor atau lebih, atau (2) kerbau/sapi sebanyak 2 ekor atau lebih, atau (3) kuda sebanyak seekor atau lebih, b) dapat menunjukkan usaha pemeliharaan/kebersihan kandang ternaknya, c) tahu cara dan dapat merawat dan memberi makan/minum ternaknya , d) tahu jenis dan menyusun rumput, daun-daunan, dan bahan ramuan lain yang baik untuk makanan ternak'),
(4, 17, 'Madya', 'a) telah memenuhi SKK Pemelihara Ternak Tingkat Purwa, b) telah memelihara ternaknya dengan baik selama sedikitnya 6 bulan, c) mengetahui jenis-jenis ternak (misalnya jenis kambing, jenis lembu dan sebagainya) sifat, tanda-tanda kebaikannya, d) mengenal beberapa jenis penyakit ternak, yang dapat/ tidak menular, tanda-tanda, sebab-sebab, pencegahan dan pengobatannya, e) mengetahui penggunaan ternaknya dengan baik, dan tahu manfaat bulunya, dagingnya, kulitnya, air susunya dan sebagainya'),
(4, 17, 'Utama', 'a) telah memenuhi SKK Pemelihara Terrnak Tingkat Madya, b) tahu cara dan dapat memilih jenis bibit ternak unggul atau pejantan yang baik, c) tahu beberapa cara meningkatkan mutu ternak, termasuk seleksi, kastrasi, efisiensi penggunaan tenaganya, perbaikan makanannya, dan sebagainya dan telah mengusahakan penyediaan makanan hijau, misalnya penanaman lamtoro, turi, nangka, dan sebagainya di sekitar rumahnya, d) telah mengusahakan, mendapatkan hasil dari pemeliharaan ternak ini, misalnya penggunaan tenaganya, menjual susu, bulu, kulit, daging dan sebagainya, dan mencatat perkembangan dan pemeliharaan ternaknya'),
(4, 18, 'Purwa', 'a) telah memelihara merpati 3 pasang atau lebih selama sedikitnya 3 bulan, b) tahu cara dan dapat mengatur dan memberi makanan serta membersihkan kandang merpati (terlebih pada musim hujan), c) tahu cara dan dapat menangkap, memegang, menerbangkan dan mengibaskan sayap burung merpati d) dapat mencegah penyakit dan pengobatannya dan menghindarkan dari gangguan lain terhadap merpati dan mencegah gangguan merpati terhadap keluarganya atau tetangganya'),
(4, 18, 'Madya', 'a) telah memenuhi SKK Pemelihara Merpati Tingkat Purwa, b) telah memelihara merpati 5 pasang atau lebih, selama sedikitnya 6 bulan, c) dapat membuat kandang merpati sederhana, dengan memperhatikan cahaya, lubang angin/ventilasi, tempat berteduh dan bertengger, d) tahu warna, jenis, dan memilih burung merpati yang baik, misalnya untuk petelur, pengirim berita, perlombaan, dan sebagainya, e) dapat memasang peluit/bunyi-bunyian (sawangan, Jawa) di tubuh merpati'),
(4, 18, 'Utama', 'a) telah memenuhi SKK Pemelihara Merpati Tingkat Madya, b) telah memelihara merpati selama satu tahun dan telah melatih terbang jauh, menyampaikan berita/surat dengan jarak lebih kurang 10 km, dan memberikan tanda (penning) pada burung c) tahu cara dan dapat menyembelih, membersihkan dan memasak burung merpati atau tahu pemasaran hasil pemeliharaan burung merpati, d) tahu cara dan telah mengadakan/mengikuti lomba terbang merpati di daerahnya, e) mempunyai catatan tentang perkembangan, kemajuan, dan hasil pemeliharaan burung merpatinya'),
(4, 20, 'Purwa', 'a) telah sedikitnya 3 bulan membuat kumpulan perangko sebanyak 200 lembar atau lebih, dari berbagai jenis, b) telah menyusun dan mengatur kumpulannya dengan rapih dan sistematis, dan menuliskan keterangan-keterangan sekedarnya (misalnya tanggal penerbitannya, masa berlakunya, dan sebagainya), c) mengetahui beberapa istilah yang banyak digunakan di kalangan pengumpul perangko (philatelis), misalnya sampul hari pertama, perforasi, roltanding, dan sebagainya'),
(4, 20, 'Madya', 'a) telah memenuhi SKK Pengumpul Perangko Tingkat Purwa, b) sedikitnya telah 6 bulan membuat kumpulan perangko sebanyak 300 lembar atau lebih dari berbagai jenis, c) telah menyusun dengan rapih, sistematis dan benar dalam album, memberikan keterangan-keterangan dan membuat daftar isi, d) dapat memperlihatkan bahwa ia mengenal perangko dari macamnya, cat air (water mark)nya, cara mencetak dan susunan warnanya'),
(4, 20, 'Utama', 'a) telah memenuhi SKK Pengumpul Perangko Tingkat Madya, b) sedikitnya telah satu tahun membuat kumpulan perangko sebanyak 500 lembar atau lebih dari berbagai jenis, c) memiliki pengetahuan yang cukup tentang perangko, misalnya sejarah perangko, tipe/jenis, kualitas, cara mengirim, dan lain-lain, d) mengetahui dan dapat menggunakan alat-alat pengumpul perangko seperti kaca pembesar/loupe, pinset, katalog, lidah perangko, dan sebagainya'),
(4, 21, 'Purwa', 'a) telah sedikitnya 3 bulan mengumpulkan dan merawat dengan baik bermacam lencana sebanyak 15 buah atau lebih, dari berbagai jenis, b) telah menyusun dan mengatur kumpulan lencananya dengan baik dan rapih, dan memberikan catatan tentang nama pemberi (asal lencana), tanggal penerimaan, tanda/lencana apa, dan sebagainya, c) mengerti gambar/warna di lencana itu, dan tahu penggunaan lencana itu'),
(4, 21, 'Madya', 'a) telah memenuhi SKK Pengumpul Lencana Tingkat Purwa, b) telah sedikitnya 6 bulan mengumpulkan dan merawat dengan baik bermacam lencana sebanyak 30 buah atau lebih, dan beberapa buah di antaranya diperoleh dari daerah lain, c) telah menyusun dan mengatur kumpulan lencananya dengan baik dan rapih, dan memberikan catatan tentang lencana itu, dengan mengingat komposisi bentuk dan warna, d) mengerti arti warna yang biasa digunakan dalam lambang-lambang'),
(4, 21, 'Utama', 'a) telah memenuhi SKK Pengumpul Lencana Tingkat Madya, b) telah sedikitnya satu tahun mengumpulkan dan merawat dengan baik bermacam lencana sebanyak 50 buah atau lebih, beberapa di antaranya didapat dari luar negeri, c) memiliki tanda/badge lambang ABRI, atau lambang daerahnya/ daerah lain/negara lain, dan mengerti serta dapat menerangkan arti gambar/warna pada tanda/lambang itu, d) dapat membuat desain lencana untuk suatu badan/lembaga/ organisasi/kepanitiaan tertentu'),
(4, 22, 'Purwa', 'a) telah mengumpulkan dan merawat dengan baik berapa jenis mata uang logam/kertas, yang masih/pernah berlaku di Indonesia, sedikitnya sejumlah 20 keping/lembar, selama 3 bulan berturt-turut, b) tahu tanggal/terbitnya, masa berlaku, tanda-tanda/kode, dan bila mungkin nama pencetak/pembuat/penerbit dan penanda tangan mata uang tersebut, c) mempunyai catatan tentang segala sesuatu mengenai mata uang itu, misalnya ukuran, berat, warna, tanda-tanda, masa berlaku dan sebagainya, d) telah mengatur mata uang tersebut dengan baik dan memberikan catatan/etiket di dekatnya'),
(4, 22, 'Madya', 'a) telah memenuhi SKK Pengumpul Mata Uang Tingkat Purwa, b) telah mengumpulkan, mengatur dan memberi keterangan jenis mata uang logam/kertas, yang masih/pernah berlaku di Indonesia/ luar negeri, sedikitnya sejumah 40 keping/lembar, selama 6 bulan berturt-turut, c) mempunyai catatan tentang segala sesuatu mengenai mata uang itu, misalnya tanggal/tahun terbitnya, masa berlakunya, tempat/ negara yang mengeluarkan, ukuran, berat, warna, desainer/ penggambar, tanda-tanda, serinya, dan lain-lain, d) dapat menggambar kasar (sketsa) berdasarkan ingatannya kedua sisi dari sedikitnya dua jenis mata uang dalam/luar negeri, dengan bagian-bagian pokoknya, misalnya huruf, angka, tandatangan nomor seri, dan lain-lain'),
(4, 22, 'Utama', 'a) telah memenuhi SKK Pengumpul Mata Uang Tingkat Madya, b) sama dengan butir 2 Tanda Kecakapan Khusus Pengumpul Mata Uang Tingkat Madya, hanya sedikitnya 75 keping/lembar selama satu tahun berturut-turut, c) mengetahui sejarah uang, macam uang yang pernah berlaku di Indonesia dengan masa berlakunya, dan sebagainya, d) mengetahui kurs mata uang kita sekarang dengan mata uang luar negeri, serta istilah keuangan lainnya, misalnya inflasi, transfer, dan sebagainya'),
(4, 23, 'Purwa', 'a) telah mengumpulkan, mengatur dan memelihara tanaman/daun/ bunga yang sudah dikeringkan dengan baik, sebanyak 25 buah atau lebih, selama sedikitnya 3 bulan, b) mengerti dan dapat menerangkan segala sesuatu tentang tanaman yang dikumpulkannya, misalnya tempat, suku/jenis, berkembang biaknya, tanda-tanda, cirinya, dan lain-lain, c) mempunyai catatan tentang tempat dan tanggal penemuan, lama pengeringan, nama tanaman, jenis/suku, tanda-tanda, sifat, masa tumbuh, dan lain-lainnya'),
(4, 23, 'Madya', 'a) telah memenuhi SKK Pengumpul Tanaman Kering Tingkat Purwa, b) telah mengumpulkan, mengatur dan memelihara tanaman/daun/ bunga yang sudah dikeringkan dengan baik, sebanyak 50 buah atau lebih, selama sedikitnya 6 bulan c) mengerti tentang nama, sifat, tanda-tanda/keistimewaan dan lain-lain dari bermacam tanaman/bagian tanaman (daun, batang, akar dan sebagainya) yang sama jenis/sukunya dengan tanaman/ bagian tanaman yang disimpannya, d) mengerti dan dapat menjelaskan cara mengeringkan bermacam-macam tanaman secara sederhana'),
(4, 23, 'Utama', 'a) telah memenuhi SKK Pengumpul Tanaman Kering Tingkat Madya, b) telah mengumpulkan, mengatur, dan memelihara tanaman/daun/ bunga yang sudah dikeringkan dengan baik, sebanyak 100 buah atau lebih, selama sedikitnya satu tahun, c) dapat memberikan penjelasan dan peragaan tentang cara pengambilan, pengeringan dan pemeliharaan tanaman kering, d) dapat menjelaskan dan memperlihatkan cara pembuatan alat-alat pengeringan tanaman'),
(4, 24, 'Purwa', 'a) telah mengumpulkan, mengatur dan memelihara dengan baik selama 3 bulan sedikitnya 10 batang dari 4 macam tanaman hidup, Misalnya macam-macam anggrek, macam-macam kaktus, macam-macam tanaman bunga, macam-macam tanaman daun kuping gajah, dan lain-lain, b) tahu cara pemeliharaannya, misalnya kebutuhan air, sinar matahari, suhu udara, hama/kelemahannya, pemupukannya, dan lain-lain, c) tahu cara mengembangbiakkannya'),
(4, 24, 'Madya', 'a) telah memenuhi SKK Pengumpul Tanaman Hidup Tingkat Purwa, b) telah mengumpulkan, mengatur dan memelihara dengan baik selama 6 bulan sedikitnya 10 batang dari 7 macam tanaman hidup, c) mempunyai catatan perkembangan/pemeliharaan tanamannya itu, dan mengetahui termasuk suku, keluarga dan jenis tanaman apa, d) tahu apa dan dapat mengembang-biakkan dengan tunas, setek, menempel, menyerbukkan, biji/benih, persemaian, dan sebagainya'),
(4, 24, 'Utama', 'a) telah memenuhi SKK Pengumpul Tanaman Hidup Tingkat Madya, b) telah mengumpulkan, mengatur dan memelihara dengan baik selama satu tahun sedikitnya 20 buah tanaman dari berbagai jenis/suku tanaman hidup, c) telah mempelajari tanaman itu, dengan membaca, menyelidiki di tempatnya sendiri/tempat lain, dan mengetahui macam-maacam jenisnya, tanda-tanda spesifiknya, dan sebagainya'),
(4, 25, 'Purwa', 'a) telah mengumpulkan satu jenis benda (misalnya bungkus/etiket rokok, kotak korek api, foto, gambar, teka-teki, guntingan koran, batu-batuan, bulu burung, motif batik/bahan pakaian, dan lain-lain) sebanyak 25 macam atau lebih, selama sedikitnya 3 bulan, b) telah menyusun dan mengatur benda-benda itu dengan baik dan rapih, dan memberikan catatan tentang benda-benda itu, misalnya tanggal penemuan, nama benda, nama pemberi, asal, jenis, keistimewaan dan lain-lain, c) dapat menjelaskan segala sesuatu tentang benda-benda kumpulannya'),
(4, 25, 'Madya', 'a) telah memenuhi SKK Pengumpul Benda Tingkat Purwa, b) telah mengumpulkan statu jenis benda (misalnya bungkus/etiket rokok, kotak korek api, foto, gambar, teka-teki, guntingan koran, batu-batuan, bulu burung, motif batik/bahan pakaian, dan lain-lain) sebanyak 35 macam atau lebih, selama sedikitnya 6 bulan c) dapat menjelaskan segala sesuatu tentang benda-benda kumpulannya'),
(4, 25, 'Utama', 'a) telah memenuhi SKK Pengumpul Benda Tingkat Madya, b) sama dengan nomor 2 untuk Tanda Tingkat Madya, tetapi sebanyak 50 macam atau lebih, selama sedikitnya 1 tahun, dan bila mungkin sebagian dari benda itu dari daerah lain atau luar negeri, c) dapat menggambar rencana (desain) (desain) etiket rokok, gambar, motif batik, bahan pakaian, atau membuat foto, tulisan, iklan, dan lain-lain, atau tahu asal, cara mendapat dan mengasah batu-batu permata'),
(4, 26, 'Purwa', 'a) telah mengumpulkan, mengatur dan memelihara dengan baik salah satu di antara bermacam-macam hewan, misalnya kupu atau serangga lain (insecta), binatang melata (reptilia), atau ikan sebanyak 5 ekor atau lebih, dari berbagai jenis, selama sedikitnya 3 bulan, b) tahu dan mempunyai catatan tentang tanggal dan tempat penemuan, nama jenis, tanda-tanda/sifat/keistimewaan kumpulannya, c) tahu cara dan dapat mengawetkan hewan-hewan itu secara kering atau basah'),
(4, 26, 'Madya', 'a) telah memenuhi SKK Pengumpul Hewan (Kering/Basah) Tingkat Purwa, b) sama dengan nomor 1 untuk Tanda Tingkat Purwa tersebut di atas tetapi sebanyak 10 ekor dari berbagai jenis, selama sedikitnya 6 bulan c) dapat menjelaskan keguanaan binatang itu bagi manusia, atau bila merusak/hama, tahu pencegahan dan pemberantasannya'),
(4, 26, 'Utama', 'a) telah memenuhi SKK Pengumpul Hewan (Kering/Basah) Tingkat Madya, b) sama dengan nomor 1 untuk Tanda Tingkat Purwa, tetapi sebanyak 20 ekor atau lebih dari berbagai jenis selama tidak kurang dari 1 tahun, c) tahu cara jenis hewan yang dipeliharanya melindungi diri dari bahaya serangan musuhnya, d) pernah memperhatikan cara hidup salah satu jenis hewan itu'),
(4, 27, 'Purwa', 'a) mengerti dan dapat mengirim tanda-tanda dengan semboyan tangan dan semboyan peluit, serta hafal abjad Morse dan Semaphore, b) mengetahui ukuran, warna tempat, waktu sikap dan cara penggunaan bendera Semaphore dan Morse beserta tongkatnya, c) dapat mengirimkan dan menerima berita dengan peluit dan huruf abjad Morse, serta dengan bendera semua huruf Semaphore yang terdiri dari sekurang-kurangnya 50 huruf, dan kesalahan maksimum 20%'),
(4, 27, 'Madya', 'a) telah memenuhi SKK Juru Semboyan Tingkat Purwa, b) tahu cara dan dapat mengirim dan menerima berita yang terdiri atas sekurang-kurangnya 75 huruf dengan bendera Semaphore dan peluit Morse berkecepatan 20 huruf tiap menit dengan kesalahan maksimal 15%. c) tahu tanda-tanda yang digunakan oleh internasional'),
(4, 27, 'Utama', 'a) telah memenuhi SKK Juru Semboyan Tingkat Madya, b) dapat mengirim berita yang terdiri atas 100 huruf dengan: (1) pesawat telegraf (kunci Morse) 30 huruf per menit, (2) dengan lampu sinar matahari (heliograf) 20 huruf per menit dengan kesalahan maksimal 15% c) dapat membuat salah satu dari alat Morse, misalnya kunci Morse dengan listrik, heliograf, dan lain-lain'),
(4, 28, 'Purwa', 'a) dapat menisik kain yang robek memanjang, berlubang (kena rokok), robek menyudut (seperti mulut katak) dan menambal kain koyak, b) dapat menjahit pakaian anak-anak/bayi, atau dapat menjahit pakaian dalam/olahraga/renang untuk diri sendiri, c) (1) mengerti bagian-bagian mesin jahit (tangan/kaki) dan pemeliharannya, dan atau (2) mengambil ukuran badan, d) mengerti dan dapat membiuat sum biasa dan sum pinggiran (open zoom)'),
(4, 28, 'Madya', 'a) telah memenuhi SKK Menjahit Tingkat Purwa, b) dapat menjahit kemeja/bawahan seragamnya sendiri, c) (1) mengerti dan dapat memperbaiki kerusakan ringan/kecil mesin jahit (tangan/kaki), dan atau (2) membuat pola dasar, d) mengerti dan dapat membuat jahitan sarung dan setik balik'),
(4, 28, 'Utama', 'a) telah memenuhi SKK Menjahit Tingkat Madya, b) dapat menjahit celana panjang (pantalon, slack, dan lain-lain) untuk diri sendiri c) dapat membuat hisan dari kain, misalnya aplikasi, lipatan hias (smock), dan lain-lain, d) dapat memotong dan menjahit pakaian untuk wanita/pria/anak'),
(4, 29, 'Purwa', 'a) (1) mengerti nama, guna dan pentingnya bagian-bagian dari sebuah sepeda, (2) mempunyai dan telah memelihara dengan baik sebuah sepeda sehingga dapat digunakan sewaktu-waktu tanpa mengalami kesulitan sedikitnya selama 6 bulan b) mengerti peraturan dan tanda-tanda lalu lintas yang banyak dipergunakan di jalan-jalan di daerahnya, c) pernah bersepeda sedikitnya sejauh 20 km untuk putra dan 15 km untuk putri, d) (1) dapat membawa benda dengan salah satu tangannya sambil mengendarai sepeda, (2) dapat naik dan turun dari sepeda, dari sisi kanan atau kiri, (3) khusus untuk putra: dapat memperbaiki kerusakan-kerusakan ringan, misalnya ban bocor, dan lain-lain'),
(4, 29, 'Madya', 'a) telah memenuhi SKK Pengendara Sepeda Tingkat Purwa, b) mengerti peraturan lalu-lintas dan semua tanda-tanda dan kode tangan di lalu-lintas, c) pernah bersepeda sedikitnya sejauh 30 km untuk putra dan 25 km untuk putri, d) (1) dapat mengendarai sepeda dengan mengenakan kain/ sarung, (2) dapat mengendari sepeda dengan menuntun sepeda lain, (3) bersama kawan lain dapat mengendarai dua buah sepeda sambil membawa sebilah bambu atau sebuah tangga, (4) dapat mengganti ban sepeda, memperbaiki pedal, bel, lampu, atau rantai yang mudah lepas'),
(4, 29, 'Utama', 'a) telah memenuhi SKK Pengendara Sepeda Tingkat Madya, b) mempunyai dan memelihara sepedanya dengan baik, sehingga dapat digunakannya tanpa kesulitan, selama sedikitnya satu tahun, c) pernah bersepeda sedikitnya sejauh 60 km untuk putra dan 35 km untuk putri, dan dilakukan dua kali, d) bersama seorang kawan dapat membuat dan mengendarai dua sepeda yang membawa sebuah tandu (draagbaar) di tengahnya, e) khusus untuk putra, dapat membongkar dan memasang kembali bagian-bagian dari sepeda, membersihkan dan memberi gemuk/ oli'),
(4, 30, 'Purwa', 'a) dapat membuat dapur dan tahu persyaratannya, b) mengetahui cara dan dapat membuat api terbuka dengan kayu tanpa minyak, c) dapat menghidangkan masakan untuk 5 orang yang terdiri dari: - nasi - satu jenis lauk kering (goreng atau bakar, tanpa kuah) - satu jenis hidangan pencuci mulut - minuman teh atau kopi panas, d) mengetahui cara menyimpan makanan menurut peraturan kesehatan, e) pernah membantu juru masak di suatu perkemahan 24 jam'),
(4, 30, 'Madya', 'a) telah memenuhi SKK Juru Masak Tingkat Purwa, b) tahu cara dan telah menyusun beberapa menu beserta bahan-bahan keperluannya, untuk satu regu yang berkemah selama maksimal 3 x 24 jam, dengan mengingat 4 sehat 5 sempurna, c) tahu cara dan dapat mengawetkan satu jenis makanan/bahan makanan, d) dapat menghidangkan masakan untuk satu regu, yang terdiri atas: - nasi, - satu jenis lauk kering (tanpa kuah, goreng/rebus/bakar/kukus, dan lain-lain) - satu jenis lauk dengan kuah (sayur), - satu jenis hidangan pencuci mulut, - minuman'),
(4, 30, 'Utama', 'a) telah memenuhi SKK Juru Masak Tingkat Madya, b) tahu cara dan telah menyusun beberapa menu untuk keperluan perkemahan satu regu selama 6 x 24 jam (lengkap dengan keperluan peralatan dan bahan), dengan mengingat 4 sehat 5 sempurna, c) mengetahui nilai gizi beberapa jenis bahan makanan, d) mengetahui cara dan dapat mengawetkan paling sedikit dua jenis makanan/bahan makanan supaya tahan selama 1 minggu'),
(4, 31, 'Purwa', 'a) tahu nama-nama perusahaan peserbangan dalam negeri dan luar negeri masing-masing paling sedikit 5 perusahaan, b) tahu nama-nama pejabat/pimpinan yang berhubungan dengan kedirgantaraan, misalnya Kepala Staf TNI-AU, Dirjen Perhubungan Udara, Dirut PT Garuda, dan lain-lain, c) tahu nama-nama pahlawan perintis kedirgantaraan (bangsa kita sendiri) paling sedikit 5 pahlawan, d) dapat menyebutkan nama-nama lapangan terbang di Indonesia, paling sedikit 5 lapangan terbang, e) tahu nama-nama bagian pokok pesawat terbang dan kegunaannya, f) tahu macam-macam motor pesawat model dan dapat menjalankan motor dengan bahan bakarnya serta tahu kapasitas mesinnya'),
(4, 31, 'Madya', 'a) telah memenuhi SKK Pencinta Dirgantara Tingkat Purwa, b) tahu yang disebut IFH dan VFR, c) dapat menjelaskan 6 dasar atmosfer yang diperhatikan dalam penerbangan, d) dapat membuat triangular course pada peta udara, e) dapat menjelaskan keguanaan kompas dalam penerbangan dan mengerti tentang True Air Speed (TAS) dan Indicator Air Speed (IAS), f) dapat menunjukkan apa yang disebut cabin, cockpit, landing gear, propeller, leading edge, trailing edge, aileron, fin, rudder, elevator, dan engine, g) dapat membantu di pangkalan udara sebagai parking master'),
(4, 31, 'Utama', 'a) telah memenuhi SKK Pencinta Dirgantara Tingkat Madya, b) tahu ketentuan-ketentuan keamanan penerbangan berdasarkan aeronautika, c) dapat menerangkan kegunaan dari fuselage, wheels, brakes, skin, wings, flaps, empenages, stabilizer, d) dapat membedakan prinsip kerja piston engine, turbo engine, jet engine dan rocket engine, e) dapat menerangkan gaya-gaya pada pesawat seperti weight, lipt, drag, f) dapat menjelaskan instrumen pesawat terbang paling sedikit instrumen-instrumen pokok (flight instrument dan engine instrument), g) tahu apa yang disebut sea plane, flying boat, land plane, amphibian, antogyro dan hellycopter'),
(4, 32, 'Purwa', 'a) dapat membuat sedikitnya satu pesawat terbang menurut skala, b) dapat membuat satu pesawat peluncur (chuck glider) dan menerbangkannya minimun 30 detik dan pernah mengikuti lomba, c) dapat menyebutkan jenis-jenis pengendalian pesawat model, d) dapat menyebutkan bahan-bahan untuk pembuatan pesawat model, e) dapat menjelaskan prinsip kerja dari pesawat model, f) dapat membuat pesawat terbang glider model dan dapat terbang minimum 60 detik'),
(4, 32, 'Madya', 'a) telah memenuhi SKK Pembuat Pesawat Model Tingkat Purwa, b) dapat menggambar bagian dari motor pesawat secara sederhana dan menyebutkan bagian-bagiannya serta jenis engine pesawat model, c) dapat menjelaskan jumlah bahan-bahan untuk pembuatan pesawat model dengan melihat gambar kerjanya dan langsung membuatnya, d) dapat membuat sedikitnya satu propeler pesawat model dan menghasilkan daya dorong, e) dapat membuat satu pesawat terbang glider model dan dapat mengatasi/mengirim pesawat tersebut sehingga dapat terbang dengan baik minimum 9 detik'),
(4, 32, 'Utama', 'a) telah memenuhi SKK Pembuat Pesawat Model Tingkat Madya, b) dapat menyebutkan jenis-jenis pesawat model yang terbang bebas (free flight), c) mengetahui jenis-jenis penutup pesawat model dan cara mengerjakannya, d) dapat dan pernah membuat salah satu dari glider model prestasi, free flight, u-control, radio control dan pernah mengikuti lomba jenis pesawat tersebut minimum tingkat daerah, e) dapat menerangkan apa sebab terjadinya stall, spin, spiral dive, dan flutter dan cara-cara mengatasinya, f) dapat mengatasi/mengirim pesawat model jenis glider/free flight (FAI power) sehingga dapat terbang dengan baik minimum 90 detik'),
(4, 33, 'Purwa', 'a) mempunyai perhatian terhadap cuaca dengan jalan membuat catatan-catatan tentang cuaca, b) tahu nama 4 macam awan dan tahu daerah ketinggiannya, c) dapat meramal/memperkirakan hari akan hujan atau tidak dengan melihat keadaan cuaca, d) dapat menjelaskan terjadinya hujan, e) pernah mengunjungi stasiun cuaca atau jawatan/bagian meteo untuk mendapat penerangan-penerangan/pelajaran-pelajaran tentang cuaca, f) tahu arti titik embun, titik beku, temperatur'),
(4, 33, 'Madya', 'a) telah memenuhi SKK Pengenal Cuaca Tingkat Purwa, b) tahu cuaca yang baik untuk penerbangan, c) dapat mengenal dengan melihat ke udara, awan tinggi, awan rendah, d) tahu apa yang disebut atrmosfer dan tahu fungsinya bagi kehidupan dunia, e) dapat menjhelaskan hubungan ketinggian dan temperatur, f) paling sedikit telah tiga kali mengunjungi stasiun cuaca atau jawatan/bagian meteo (sipil atau militer) untuk mendapatkan penerangan-penerangan / penjelasan-penjelasan tentang cuaca, g) tahu tanda-tanda daerah/tempat terjadinya thermic dan dapat menjelaskan kepada orang lain'),
(4, 33, 'Utama', 'a) telah memenuhi SKK Pengenal Cuaca Tingkat Madya, b) dapat menjelaskan mengapa pilot selalu memperhatikan keadaan cuaca, c) mengenal di udara atau melalui foto-foto atau gambar-gambar 10 bentuk awan (tinggi sedang, rendah, vertikal), d) dapat membaca dan membuat laporan cuaca dengan kode-kode menurut CAA (Civil Aeronautica Administration) dan mengajarkan kode-kode itu kepada paling sedikit 2 orang temannya, e) dapat menjelaskan kode warna yang dipakai untuk membedakan macam-macam presipitasi pada peta cuaca, f) tahu pengaruh hujan, hujan es, kilat, kabut terhadap pesawat dan angin pada waktu terbang, g) telah mengunjungi stasiun cuaca (sipil atau militer) dan dapat menjelaskan alat yang bagaimana digunakan untuk mendapatkan data-data cuaca, h) dapat menjelaskan wind direction, wind velocity, visibility, VFR, IFR, radio weather code'),
(4, 34, 'Purwa', 'a) hafal fonetik alfabet (A=alpha, B=bravo, C=charlie, dan seterusnya) dapat menerangkan mengapa dipakai itu, b) tahu arti alat-alat telekomunikasi sebagai berikut: telegraf, telepon, teletype (telex), faksimili, televisi (semua ini adalah alat-alat telekomunikasi dengan kawat/radio), c) tahu abjad Morse dan tahu sejarah penciptanya, yaitu Samuel Finley Morse, d) dapat menyampaikan berita dengan lisan secara cepat dan tepat, e) dapat mengirim berita melalui telepon'),
(4, 34, 'Madya', 'a) telah memenuhi SKK Komunikasi Tingkat Purwa, b) tahu kegunaan elektromagnetik pada alat radio, telepon, bel listrik, c) tahu apa yang dimaksud dengan: (1) taxiing dan take off instruction, (2) take off clearence, (3) landing instruction, (4) position report, d) tahu kode-kode yang digunakan untuk laporan cuaca, e) dapat mengirim dan menerima semboyan Morse dengan peluit atau alat lain, f) dapat memberi keterangan dan memanggil dokter dengan jelas menggunakan telepon atau alat lain'),
(4, 34, 'Utama', 'a) telah memenuhi SKK Komunikasi Tingkat Madya, b) dapat mengirim dan menerima telegram (dengan kode Morse), c) menunjukkan kecakapannya dalam mengirim dan menerima berita kode Morse paling sedikit 5 kata tiap menit selama paling sedikit 5 menit, tiap kata paling sedikit 5 huruf, d) dapat membuat atau mengetik surat-surat telegram atau teleks'),
(4, 35, 'Purwa', 'a) dapat menggambar pesawat terbang dari 3 pandangan, b) mengetahui macam bahan yang dipakai membuat rangka pesawat terbang, c) mengerti prinsip-prinsip membuat pesawat terbang, d) dapat menyebutkan win grib, wing spor dan keguanannya, e) dapat menerangkan bentuk badan pesawat terbang yang disebut monoqoqus dan frame work'),
(4, 35, 'Madya', 'a) telah memenuhi SKK Konstriksi Pesawat Udara Tingkat Purwa, b) membuat catatan-catatan tentang pengetahuan konstruksi pesawat terbang dalam buku catatannya, c) membuat pesawat terbang padat (solid) dengan bagian-bagian pokok yang serasi, d) dapat menggambarkan dan menyebutkan macam-macam bentuk bagian-bagian pokok pesawat terbang, e) dapat menyebutkan pada umumnya alat-alat yang dipakai untuk mereparasi (memperbaiki) pesawat terbang'),
(4, 35, 'Utama', 'a) telah memenuhi SKK Konstruksi Pesawat Udara Tingkat Madya, b) dapat menerangkan bagian-bagian dari pesawat terbang secara keseluruhan (wing span, chord line, akar sayap, ujung pesawat, trailing edge, leading edge, wing flap, spoiler, nose, cockpit, alat pendarat, pemantap tegak, dan pemantap darat), c) dapat menyebutkan lampu-lampu yang ada di pesawat dan kegunaannya, d) dapat menyebutkan alat-alat untuk menggerakkan kemudi pesawat terbang'),
(4, 36, 'Purwa', 'a) tahu prinsip mesin 2 langkah dan mesin 4 langkah, b) mengerti cara kerja mesin pesawat model dan macam-macam mesin pesawat model, c) mengerti kegunaan mesin pada pesawat terbang, d) dapat menjelaskan instrumen mesin yang harus ada di pesawat terbang, e) dapat menjelaskan sistem yang harus ada di suatu mesin, baik mesin mobil maupun mesin pesawat terbang'),
(4, 36, 'Madya', 'a) telah memenuhi SKK Juru Motor Pesawat Terbang Tingkat Purwa, b) tahu prinsip mesin pada umumnya dan tahu prinsip mesin piston, mesin jet, dan mesin roket, c) dapat menjelaskan pengaruh ketinggian terhadap mesin piston, mesin jet, dan mesin roket, d) mengerti fungsi propeler dari mesin pesawat terbang, e) dapat menjelaskan sistem pendingin, sistem penyalaan, sistem peredaran bahan bakar dan sistem pelumas bagi mesin piston pesawat terbang, f) tahu perbedaan antara mesin berpendingin udara dan pendingin zat cair'),
(4, 36, 'Utama', 'a) telah memenuhi SKK Juru Motor Pesawat Terbang Tingkat Madya, b) dapat menerangkan keuntungan maupun kerugian jika pesawat menggunakan mesin jet dan mesin piston, c) tahu bagian-bagian utama dari suatu mesin jet dan kegunaan dari bagian-bagian itu, d) dapat menerangkan tentang turbo prop, turbo jet dan fan, e) dapat menjelaskan bahan bakar yang digunakan untuk mesin piston, mesin jet dan mesin roket, f) dapat menjelaskan perhitungan power dari mesin piston'),
(4, 37, 'Purwa', 'a) tahu tiga cara bernavigasi, b) tahu yang disebut true north, compass north, c) dapat mengerti arah angin di tanah dengan melihat tanda-tanda yang ditunjukkan kepadannya, d) dapat membaca peta jalan/biasa, e) tahu alat-alat yang digunakan untuk mengetahui arah angin di tanah'),
(4, 37, 'Madya', 'a) telah memenuhi SKK Navigasi Udara Tingkat Purwa, b) tahu 16 arah mata angin dan dapat menunjukkan arah dengan derajat dan dapat menggunakan kompas, c) tahu apa yang disebut true course, compass course, air speed, ground speed, wind direction, d) tahu tanda-tanda peta udara, e) pernah mengadakan/mengikuti cross country dengan kompas'),
(4, 37, 'Utama', 'a) telah memenuhi SKK Navigasi Udara Tingkat Madya, b) tahu arti pelotage, dead rechesing, celestial, navigation, c) dapat membaca peta, topografi dan peta air, d) tahu arti magnetic bearing, wind velocity, altitude, longitude, variasi dan deviasi, e) dapat membuat peta pangkalan atau lapangan yang digunakan sebagai landasan darurat, f) dapat membaca tanda-tanda/simbol di peta udara dan dapat memberikan paling sedikit 5 macam tanda di tanah yang dapat dilihat oleh pilot untuk menentukan wind direction di tanah'),
(4, 38, 'Purwa', 'a) tahu ketentuan-ketentuan kondisi badan bagaimana yang boleh dan tidak boleh naik pesawat terbang, b) tahu cara mengatur orang sakit di darat yang akan diangkut dengan pesawat terbang, c) dapat membedakan pesawat-pesawat yang menggunakan pressurevise dan tidak pressurevise, d) dapat mengangkut (naik dan turun) orang sakit ke dalam dan ke luar pesawat'),
(4, 38, 'Madya', 'a) telah memenuhi SKK Evakuasi Medis Dirgantara Tingkat Purwa, b) dapat menyiapkan alat medis yang diperlukan untuk evakuasi medis, c) tahu persyaratan pesawat terbang yang baik untuk dipergunakan dalam evakuasi medis, d) tahu siapa saja yang harus mendapat pengawasan khusus dalam evakuasi medis, e) dapat membagi prioritas terhadap penderita yang memerlukan evakuasi medis'),
(4, 38, 'Utama', 'a) telah memenuhi SKK Evakuasi Medis Dirgantara Tingkat Madya, b) dapat bertindak cepat apabila ada keadaan darurat di dalam/ ketika melaksanakan evakuasi medis, c) tahu apa yang boleh dan apa yang tidak boleh dilaksanakan/ diberikan dalam evakuasi medis, d) dapat menerangkan bahaya-bahaya penerbangan terhadap human factor (faal tubuh manusia), e) mempunyai ijasah PPPK dari PMI/badan yang sah atau keterangan yang sejenis dari seorang flight surgeon'),
(4, 39, 'Purwa', 'a) mempunyai catatan mengenai pesawat yang pernah dilihatnya, lengkap dengan tanggal dan di mana, serta ciri-ciri khusus dari sedikitnya lima pesawat, b) dapat menyebutkan paling sedikit lima perusahaan penerbangan dalam/luar negeri, c) dapat menyebutkan pesawat yang digunakan untuk transporttasi komersial paling sedikit lima pesawat terbang, d) dapat menyebutkan paling sedikit 10 pesawat yang bersayap sweep back'),
(4, 39, 'Madya', 'a) telah memenuhi SKK Pengenal Pesawat Terbang Tingkat Purwa, b) dapat menyebutkan dan menggambarkan bagian-bagian pokok pesawat terbang, c) dapat menyebutkan roda-roda pendarat yang dapat dilipat dan tidak dapat dilipat paling sedikit 5 pesawat, d) dapat menyebutkan pesawat yang menggunakan tipe nose wheel dan tail wheel paling sedikit 5 pesawat, e) dapat menyebutkan paling sedikit 5 pesawat yang bersayap delta'),
(4, 39, 'Utama', 'a) telah memenuhi SKK Pengenal Pesawat Terbang Tingkat Madya, b) dapat menyebutkan 5 industri pesawat terbang dan pesawat yang dihasilkannya, c) dapat menyebutkan roda-roda pendarat utama (main wheel) yang dipasang di sayap dan di badan paling sedikit 5 pesawat, d) dapat menyebutkan sayap di atas (high wing), sayap di tengah (middle wing) dan sayap di bawah (low wing) paling sedikit 5 pesawat'),
(4, 40, 'Purwa', 'a) telah memenuhi SKK Petani Padi untuk Pramuka golongan Siaga, b) tahu dan dapat: (1) memilih/memisahkan benih padi yang baik untuk ditanam, (2) memilih bibit padi yang baik dan sehat di pesemaian, (3) menanam padi dengan teratur (tandur jajar) (4) menyiangi padi (dengan tangan atau alat) (5) melakukan penanaman padi dengan baik, c) tahu dan dapat mencampur obat (dosis) dan menggunakan sedikitnya satu macam obat/alat pemberantas hama/penyakit padi'),
(4, 40, 'Madya', 'a) telah mememenuhi SKK Petani Padi untuk Tingkat Purwa, b) tahu dan mengerti tentang: (1) fase-fase pertumbuhan padi, (2) waktu dan cara penggunaan pupuk (buatan/alam) dan cara penyimpanan pupuk, (3) waktu dan cara pengaturan air untuk persemaian dan untuk sawah, (4) waktu dan cara penyiangan padi, (5) waktu dan cara panenan padi, c) tahu dan mengerti cara penggunaan obat pemberantas hama/ penyakit padi dan cara penyimpanan obat tersebut'),
(4, 40, 'Utama', 'a) telah mememenuhi SKK Petani Padi untuk Tingkat Madya, b) tahu dan mengerti tentang: (1) waktu dan cara pengolahan tanah, (2) waktu dan cara pembuatan pesemaian, (3) penggunaan alat pengolah tanah dan pemeliharaan alat itu, (4) penggunaan alat pemberantasan hama serta pemeliharaan alat tersebut, (5) cara pembuatan garis tandur jajar, c) tahu dan mengerti masalah penyimpanan, pengangkatan, dan pemasaran hasil panenan'),
(4, 41, 'Purwa', 'a) menggunakan kompas atau alat lain untuk mecari arah kiblat, b) membuat denah bangunan tempat tinggalnya atau bangunan lain (satu tingkat), termasuk halamannya dengan skala tertentu, c) mengerti beberapa macam tanda-tanda di peta, misalnya gunung, sungai, kota, batas wilayah, dan sebagainya, d) membuat sketsa peta wilayah sekitar tempat tinggalnya dengan radius sedikitnya 1 km dan menunjukkan letak tempat-tempat penting, misalnya pasar, masjid/gereja, sekolah, lapangan olahraga, Puskesmas/balai kesehatan, dan sebagainya'),
(4, 41, 'Madya', 'a) telah mencapai TKK Juru Peta untuk Tingkat Purwa, b) dapat menggunakan kompas bidik (vizier compass), c) dapat membuat peta lapangan dengan skala tertentu, dengan memasukkan segala sesuatu yang ada di lapangan itu, misalnya pohon, tenda, bangunan, dan sebagainya, d) dapat membuat peta-pita dari perjalanannya sejauh 3 km dengan mencatat semua tempat penting yang ada di kiri kanan jalan yang dilaluinya, e) dapat menaksir jarak/jauh dengan beberapa cara'),
(4, 41, 'Utama', 'a) telah mencapai SKK Juru Peta Tingkat Madya, b) dapat membuat peta lapangan secara triangulasi (dengan segitiga-segitiga) dengan menggunakan kompas prisma atau kompas bidik, c) dapat mengubah peta-pita menjadi peta daerah dengan skala tertentu, dan menggunakan tanda-tanda peta yang umum dipakai di peta topografi, d) dapat menggunakan peta topografi untuk jalan menuju suatu tempat dengan koordinat yang ditentukan oleh penguji dengan memilih sendiri jalan yang akan ditempuhnya, berdasarkan tanda-tanda yang ada di peta itu, e) dapat menggambar dan membaca peta pemandangan (panorama schets)'),
(4, 42, 'Purwa', 'a) mempunyai/telah mencapai TKK Pelaut Tingkat Purwa b) mengerti abjad Morse dan dapat menerima dengan alat optik, dalam kecepatan 25 huruf per menit, c) mengerti perbedaan kompas magnit, dan kompas giro dan mengerti apa yang disebut Utara Sejati dan Utara Magnit d) mengetahui 3 buah alat navigasi dan mengerti gunanya'),
(4, 42, 'Madya', 'a) telah memenuhi SKK Navigasi Laut Tingkat Purwa dan TKK Pelaut Tingkat Madya, b) dapat menghitung arah suatu benda di laut/di lapangan dengan mempergunakan kompas, c) dapat menunjukkan 3 gugusan bintang di langit, dan mengetahui saat-saat terbitnya, misalnya: bintang Waluku (Orion), bintang Salib Selatan (Zuiderkruis, Gubug Penceng), bintang Biduk/Perahu (Grote Beer), d) mengerti dan dapat menghitung perbedaan Utara Magnetis dan Utara Sejati, serta vonasi dan deviasi'),
(4, 42, 'Utama', 'a) telah memenuhi SKK Navigasi Laut Tingkat Madya, b) mengetahui bentuk dan warna rambu-rambu di daerahnya serta tahu maksudnya, c) mengerti peraturan dan pelanggaran laut, d) dapat membaca peta laut di daerahnya, dan dapat menunjukkan di peta itu gunung, rambu, teluk, di daerahnya, e) dapat menentukan di peta daerahnya posisi sebuah benda dengan menggunakan alat pembaring'),
(4, 43, 'Purwa', 'a) memahami abjad Semaphore dan Morse, b) dapat membuat menara isyarat sederhana, c) memahami isyarat peluit laut, d) dapat menerima isyarat dengan bendera'),
(4, 43, 'Madya', 'a) telah memenuhi SKK Juru Isyarat Bendera Tingkat Purwa, b) dapat mengirim dan menerima isyarat/tanda-tanda dengan bendera, c) dapat membuat peralatan isyarat bendera'),
(4, 43, 'Utama', 'a) telah memenuhi SKK Juru Isyarat Bendera Tingkat Madya, b) mengetahui hubungan komunikasi nasional/internasional, c) memahami isyarat bendera internasional'),
(4, 44, 'Purwa', 'a) memahami bagian-bagian kapal dan mempunyai koleksi cap/ tanda-tangan nakhoda, b) memahami perahu layar rakyat, dan dapat mengendalikan/ mengemudikan dengan baik, c) mengetahui dan dapat menggunakan peralatan keselamatan, d) memahami tanda-tanda peluit, misalnya tanda panggilan/apel, tanda penghormatan, dan lain-lain, e) memahami tali-temali dan kualitas dari kapal untuk mempelajari peralatan dan perbaikan ringan setelah latihan/penggunaan'),
(4, 44, 'Madya', 'a) telah memenuhi TKK Pelaut Tingkat Purwa, b) aktif dalam pelayarannya masing-masing dalam latihan maupun mengikuti pelayaran rakyat (dengan sepengetahuan pembina/ pengujinya), dan memiliki catatan kunjungan/buku pelaut, c) memahami peta/membaca peta, terutama daerahnya sendiri dan tanda-tanda bahaya/rambu yang dipasang syahbandar, dengan tambahan navigasi sedang, penggunaan kompas, stopwatch, dan lain-lain d) memahami lalu-lintas pelayaran dalam pelabuhan (kesyahbandaran)'),
(4, 44, 'Utama', 'a) telah memenuhi SKK Pelaut Tingkat Madya, b) memahami bentuk-bentuk perahu layar olahraga yang ada di Indonesia dan peraturan pertandingan olahraga layar dan dayung dari Peropi, c) mendalami perawatan dan perbaikan sebuah perahu/kapal untuk kepelautan/dok, termasuk perawatan layar, d) memahami arus lalu-lintas pelayaran niaga yang menuju daerahnya masing-masing, pelayaran rakyat maupun nasional/internasional'),
(4, 45, 'Purwa', 'a) memahami abjad Morse, b) memahami etiket penyiaran radio komunikasi, c) mengerti isyarat peluit laut, d) dapat menerima isyarat listrik'),
(4, 45, 'Madya', 'a) telah memenuhi SKK Juru Isyarat Listrik Tingkat Purwa, b) dapat mengirim dan menerima isyarat listrik, c) memahami perbaikan dari pesawat pemancar/penerima, d) dapat membuat alat pemancar/penerima secara sederhana'),
(4, 45, 'Utama', 'a) telah memenuhi SKK Juru Isyarat Listrik Tingkat Madya, b) mengetahui perawatan pemancar/penerima, baik kepunyaan sendiri atau kepunyaan orang lain/instansi, c) memahami rencana komunikasi yang sudah dilakukan dan yang akan datang, d) memahami isyarat-isyarat internasional'),
(4, 46, 'Purwa', 'a) memahami abjad Morse, b) memahami isyarat peluit pelaut, c) dapat menerima isyarat dengan optik'),
(4, 46, 'Madya', 'a) telah memenuhi SKK Juru Isyarat Optik Tingkat Purwa, b) dapat mengirim dan menerima tanda-tanda/isyarat optik, c) dapat membuat alat optik sederhana untuk memberikan isyarat'),
(4, 46, 'Utama', 'a) telah memenuhi SKK Pengumpul Juru Isyarat Optik Tingkat Madya, b) memahami jalur hubungan komunikasi, c) memahami peralatan komunikasi dan tahu cara penggunaannya, d) memahami isyarat-isyarat internasional'),
(4, 47, 'Purwa', 'a) memahami setiap gambar dari perahu, kapal niaga, dan kapal perang Indonesia/asing, b) dapat membuat maket dari beberapa jenis perahu layar khas Indonesia, c) memahami setiap bagian dari kapal/perahu dan penggunaannya, d) memahami jenis-jenis kapal yang ada di Indonesia mengenai daya dorongnya, misalnya kapal uap, mesin/motor, layar, dan sejenisnya'),
(4, 47, 'Madya', 'a) telah memenuhi SKK Perencana Kapal Tingkat Purwa, b) memahami peralatan sederhana maupun modern untuk berlayar, c) memahami gambar-gambar tulang pembuatan kapal dengan perhitungan ilmu pasti dan ilmu gaya, d) menyebarluaskan hasil penelitian perhitungan pembuatan kapal modern dalam media tertentu'),
(4, 47, 'Utama', 'a) telah memenuhi SKK Perencana Kapal Tingkat Madya, b) telah menghasilkan sedikitnya sebuah perahu yang direncanakan dan dibuatnya sendiri, dan telah dicoba untuk digunakan sendiri, c) dapat memberikan latihan dan penjelasan mengenai salah satu pokok/nomor dari Syarat Kecakapan Khusus Perencana Kapal Tingkat Purwa kepada kelompok Pramuka, d) prestasi yang dihasilkan mempunyai taraf nilai nasional'),
(4, 48, 'Purwa', 'a) mengenal tipe out boat, b) mengenal perlengkapan dari out boat, dan tahu cara penggunaannya, c) mempunyai keberanian untuk ikut berlayar'),
(4, 48, 'Madya', 'a) telah memenuhi SKK Perahu Motor Tingkat Purwa, b) dapat mendayung atau mengemudikan perahu/motor boat, c) dapat mengolah gerak perahu untuk merapat, d) mengenal waktu-waktu pasang surut dan keadaan cuaca'),
(4, 48, 'Utama', 'a) telah memenuhi SKK Perahu Motor Tingkat Madya, b) dapat mengerjakan pemeliharaan perahu motor, c) dapat mengerjakan perbaikan ringan pada mesin/motornya, d) mengenal peraturan/pelanggaran laut (misalnya garis pelayaran yang ditentukan syahbandar), e) dapat membantu perahu motor berlayar dengan pedoman yang ada pada out boat'),
(5, 1, 'Purwa', 'a) telah mengetahui cara menolong kebakaran dengan alat dan bahan yang ada, b) dapat memberitahu dengan cepat kepada yang berwajib kalau terjadi suatu kebakaran, c) mengetahui jenis-jenis alat pemadam kebakaran, d) mengetahui bahan-bahan untuk memadamkan api, e) dapat mengambil tindakan untuk menolong orang lain yang menderita kecelakaan karena api'),
(5, 1, 'Madya', 'a) telah memenuhi SKK Pemadam Kebakaran Tingkat Purwa, b) dapat melaksanakan petunjuk-petunjuk dari petugas pemadam kebakaran untuk menyelamatkan orang-orang dan harta benda dari adanya kebakaran, c) dapat memperkirakan lokasi daerah kebakaran, d) dapat mengetahui cara-cara mempergunakan alat-alat pemadam kebakaran berikut perlengkapannya, e) dapat menerapkan kecakapan PPPK untuk menolong orang lain karena menderita luka akibat dari kebakaran'),
(5, 1, 'Utama', 'a) telah memenuhi SKK Pemadam Kebakaran Tingkat Madya, b) dapat memadamkan kebakaran kompor, kebakaran listrik, kebakaran mesin mobil dan lain-lain perabot yang dapat menimbulkan kebakaran, c) mengetahui tempat dan alamat, nomor telepon (kalau ada), pos-pos pemadam kebakaran, d) pernah mengikuti kursus/latihan pemadam kebakaran yang diadakan oleh Dinas Pemadam Kabakaran, e) mengetahui organisasi tentang pemadam kebakaran dari pusat sampai jajaran (eselon) terendah'),
(5, 2, 'Purwa', 'a) dapat memberi penjelasan kepada orang lain tentang peraturan lalu lintas yang berlaku bagi pengemudi-pengemudi kendaraan bermotor, dan yang berlaku bagi pengemudi-pengemudi kendaraan tak bermotor, b) menjelaskan asas-asas disiplin dan kesopanan lalu lintas, c) mengenal dan tahu tentang kegunaan SIM (Surat Ijin Mengemudi)'),
(5, 2, 'Madya', 'a) telah mencapai TKK Pengaman Lalu Lintas untuk Tingkat Purwa, b) dapat memberi pertolongan pertama pada waktu terjadi kecelakaan lalu lintas, c) dapat menyeberangkan sekelompok anak-anak atau barisan anak-anak, d) dapat bertindak pada waktu terjadinya kecelakaan lalu lintas dan tahu kepada siapa harus melaporkan, e) membantu petugas-petugas polisi lalu lintas bila tahu terjadi kemacetan lalu lintas'),
(5, 2, 'Utama', 'a) telah memenuhi SKK Pengaman Lalu Lintas Tingkat Madya, b) mengerti tentang pengetahuan pokok lalu lintas dan angkutan jalan raya, c) pernah membantu Polisi Lalu Lintas melakukan pengamanan serta pemeriksaan tempat-tempat terjadinya suatu kecelakaan lalu lintas, d) mampu menggunakan walky talky, e) memiliki SIM'),
(5, 3, 'Purwa', 'a) dapat membuat kentongan dan menerangkan kepada masyarakat sekitarnya tentang pentingnya kentongan sebagai tanda-tanda bahaya, berikut tanda-tandanya, b) membantu sedikitnya tiga kali melakukan ronda malam di kampung/desanya'),
(5, 3, 'Madya', 'a) telah mencapai TKK Pengaman Kampung/Desa untuk Tingkat Purwa, b) telah membuat laporan atau melaporkan suatu peristiwa tindak pidana yang terjadi di kampung/desanya kepada yang berwajib, c) pernah membantu petugas keamanan dalam upacara, keramaian, pesta, atau di masjid yang berada di kampung/desanya, d) mengamankan tempat atau lokasi kejadian untuk barang bukti'),
(5, 3, 'Utama', 'a) telah memenuhi SKK Pengaman Kampung/Desa Tingkat Madya, b) pernah menjalankan latihan olahraga bela diri, c) mengenal pokok-pokok tentang menjalankan penyelidikan dengan sidik jari, d) mengetahui perbedaan tugas pokok polisi, jaksa dan hakim, e) pernah membuat sketsa tentang suatu kejadian/peristiwa tindak pidana'),
(5, 4, 'Purwa', 'a) dapat menggambar sketsa daerah kecamatan/kabupaten (tergantung kepadatan penduduknya), serta jalan-jalan menuju ke ibukota kecamatan, kabupaten-kabupaten lain yang berdekatan, b) tahu dan dapat menjelaskan jalan ke: (1) rumah RT/RW/Lurah, (2) Pos Polisi, Hansip, Keamanan Kampung, (3) Pos Pemadam Kebakaran, (4) Pos PPPK, rumah sakit, dokter, apotik, PMI (5) tempat ibadat, pasar, toko, (6) stasiun bis, kereta api, taksi, oplet, dan route/jamnya (7) hotel/losmen, restoran, warung-warung, c) dapat mengantar orang lain ke salah satu tempat tersebut nomor 2 pada jarak maksimum 5 km untuk daerah yang padat penduduknya, dan 10 km untuk daerah berpenduduk jarang, d) dapat menunjukkan jalan-jalan (dan bila ada nama baru dan lama jalan tersebut) sedikitnya di daerah/wilayah kelurahannya'),
(5, 4, 'Madya', 'a) telah mencapai TKK Penunjuk Jalan untuk Tingkat Purwa, b) dapat menggambar sketsa daerah propinsinya, dengan jalan-jalan kereta api, jalan-jalan raya, tempat-tempat bersejarah, dan lain-lain, c) tahu dan dapat menjelaskan jalan-jalan ke: (1) kantor kecamatan/kabupaten, (2) perusahaan-perusahaan besar, (3) kantor instansi pemerintah (sipil/militer) tingkat kabupaaten, (4) tempat-tempat bersejarah, (5) bengkel-bengkel sepeda, motor, mobil, dan dapat mengantar orang lain ke tempat-tempat penting, dengan jarak maksimal 20 km, d) mempunyai catatan tentang alamat dan nomor telepon dari tempat-tempat penting, di daerahnya, atau di tempat mencari dalam buku daftar telepon, e) mengetahui sedikit-sedikitnya tentang sejarah dan peninggalan sejarah di daerahnya'),
(5, 4, 'Utama', 'a) telah memenuhi SKK Penunjuk Jalan Tingkat Madya, b) dapat menunjukkan gedung-gedung penting, lapangan olahraga, kolam renang, peristirahatan, tempat-tempat rekreasi, rumah-rumah pejabat dan sebagainya, c) mempunyai catatan singkat mengenai keadaan daerahnya, perkembangan penduduk, kemajuan produksi pertanian, peternakan, kepariwisataan, keadaan sungai, pantai, gunung, sejarahnya dan sebagainya, d) dapat mengantarkan orang lain ke tempat-tempat penting, di daerahnya dalam jarak 30 km dari tempat tinggalnya'),
(5, 5, 'Purwa', 'a) telah mememenuhi SKK Juru Bahasa untuk golongan Siaga, b) dapat menyusun suatu karangan dalam bahasa Inggeris, Jerman, Perancis, Spanyol, Italia, Jepang, Cina atau Arab, c) dapat menceritakan suatu peristiwa yang dilihat, didengar atau dirasakannya, dengan menggunakan bahasa Inggeris, Jerman, Perancis, Spanyol, Italia, Jepang, Cina atau Arab d) dapat menterjemahkan dari buku, majalah atau surat kabar dari bahasa Inggeris, Jerman, Perancis, Spanyol, Italia, Jepang, Cina atau Arab ke bahasa Indonesia, dengan diperkenankan menggunakan kamus'),
(5, 5, 'Madya', 'a) telah mencapai TKK Juru Bahasa untuk Tingkat Purwa, b) dapat mengarang surat biasa, surat undangan, surat terima kasih, surat bela sungkawa, surat ucapan selamat, dalam bahasa Inggeris, Jerman, Perancis, Spanyol, Italia, Jepang, Cina atau Arab, c) dapat membacakan dan menerjemahkan tanpa menggunakan buku kamus, suatu teks pidato tertulis dalam bahasa Inggeris, Jerman, Perancis, Spanyol, Italia, Jepang, Cina atau Arab ke bahasa Indonesia, dan sebaliknya dari bahasa Indonesia ke bahasa asing tersebut'),
(5, 5, 'Utama', 'a) telah memenuhi SKK Juru Bahasa Tingkat Madya, b) dapat memberi ceramah dalam bahasa Inggeris, Jerman, Perancis, Spanyol, Italia, Jepang, Cina atau Arab, termasuk memberi jawaban atas pertanyaan-pertanyaan pendengar ceramah, c) mempelajari sebuah buku berbahasa Inggeris, Jerman, Perancis, Spanyol, Italia, Jepang, Cina atau Arab, dan membicarakan isi buku itu dengan Penguji dalam bahasa asing tersebut, d) pernah menjadi juru bahasa menerjemahkan pembicaraan seorang dalam bahasa Inggeris, Jerman, Perancis, Spanyol, Italia, Jepang, Cina atau Arab'),
(5, 7, 'Purwa', 'a) dapat menyiapkan tempat dan alat-alat untuk memandikan anak/ bayi, misalnya alas perlak, handuk, lap air (waslap), sabun, bedak talk, pakaian bersih, dan tahu cara/mengetahui hangatnya air, b) dapat membuat dan menyiapkan minuman/makanan untuk anak/ bayi, menyuapinya, serta tahu cara dan waktu pemberiannya, c) dapat menjaga, menghibur, merawat, mengganti pakaian dan menidurkan anak/bayi'),
(5, 7, 'Madya', 'a) telah mencapai TKK Perawatan Anak untuk Tingkat Purwa, b) tahu cara dan dapat memegang dan memandikan anak/bayi, membersihkan dubur/alat kelamin, serta memelihara kuku, dan kulit bayi, c) tahu syarat-syarat gizi dan memelihara makanan anak/bayi, d) tahu cara dan dapat memelihara kesehatan anak/bayi, misalnya mencegah jangan sampai masuk angin, panas, tergeliat, terkilir, kejang, cacingan, dan sebagainya'),
(5, 7, 'Utama', 'a) telah mencapai SKK Perawat Anak Tingkat Madya, b) tahu cara dan dapat mencegah dan menolong anak yang mengalami kejang, demam dan merawat luka-luka kecil, c) dapat melatih anak kebersihan, kerapihan, sopan santun, suka bekerja, dan disiplin diri sendiri, d) tahu dan dapat mencarikan permainan, alat-alat bermain yang cocok dengan pribadi dan watak anak, dan berguna bagi perkembangan jasmani dan rohani anaknya'),
(5, 8, 'Purwa', 'a) mengerti dan telah melaksanakan, peraturan kesehatan di rumahnya, misalnya kebersihan rumah dan halaman, tempat sampah, hubungan air, kamar mandi, kakus, sumur, dan sebagainya, b) mengerti dan dapat melakukan: (1) pengukuran suhu badan (dengan thermometer), (2) meraba dan menghitung denyut nadi dan pernafasan, (3) menggunakan steekpan, pispot, botol air kencing, (4) penyediaan ruang dan tempat untuk orang sakit, misalnya tempat tidur, meja, bel, dan lain-lain, c) mengetahui cara perawatan penderita sebelum/sesudah pemeriksaan dokter, dan tahu hal-hal yang perlu dicatat/ diperhatikan/dilaporkan kepada dokter'),
(5, 8, 'Madya', 'a) telah mencapai TKK Perawatan Keluarga untuk Tingkat Purwa, b) mengerti dan dapat melakukan perawatan bagi orang sakit, yaitu: (1) membaringkan, mendudukkan, membalikkan badan penderita, (2) menyiapkan dan menyuapi makanan minuman pada penderita, (3) memberikan sandaran punggung (ruggesteun), penumpang kaki, paha dan tangan, (4) dapat mengganti alas tempat tidur (seprei), perlak dan selimut yang sedang dipakai oleh penderita, (5) menggunakan kompres panas/dingin secara basah/kering secara tepat/baik, c) mengerti cara pencegahan dan penularan beberapa jenis penyakit'),
(5, 8, 'Utama', 'a) telah mencapai TKK Perawatan Keluarga Tingkat Madya, b) mengerti dan dapat melakukan perawatan bayi, misalnya menyiapkan alat dan tempat memandikan, mengganti pakaian, cara memegang/mendukung, membungkus dengan selimut, dan sebagainya, c) mengerti dan dapat melakukan perawatan penderita (atas nasehat/petunjuk dokter): (1) menyeka/memandikan penderita, (2) memberikan obat-obat tertentu, (3) memberikan uap panas, (4) memindahkan, menurunkan penderita dari tempat tidur dan mendudukkan di kursi, (5) membantu penderita berjalan, d) mengerti dan dapat menggunakan persediaan obat-obatan dan alat-alat perawatan keluarga di rumah'),
(5, 9, 'Purwa', 'a) dapat menulis surat undangan, menjawab dapat/tidak dapat menerima undangan dan menulis surat ucapan terima kasih, b) tahu cara menerima, duduk, berbicara, memperkenalkan dan mengantar tamu, c) dapat dapat mengatur tempat dan meja tamu, memilih, menyusun, dan mengatur makanan dan minuman untuk tamu, serta membuat acara “jamuan minum teh” (bertandang/berkunjung)'),
(5, 9, 'Madya', 'a) telah mencapai TKK Penerima Tamu untuk Tingkat Purwa, b) tahu dan dapat melaksanakan kewajiban sebagai tuan/nyonya rumah mempersiapkan dan menerima tamu, yang bermalam atau lebih, c) tahu dan dapat bertindak sebagai tamu yang baik di mana-mana, d) tahu waktu-waktu untuk berkunjung/bertandang, dan saat harus mengakhiri kunjungan ke rumah orang lain, dan mengakhiri kunjungan orang lain di rumahnya, e) dapat menyusun meja makan, menyusun menu, memilih makanan dan mengajak makan bersama tamunya'),
(5, 9, 'Utama', 'a) telah mencapai TKK Penerima Tamu Tingkat Madya, b) tahu cara dan dapat mengatur segala sesuatu untuk acara bayi lahir, ulang tahun, perkawinan, kematian, dan lain-lain sesuai dengan adat-istiadat setempat di daerahnya, c) tahu cara dan dapat membuat acara untuk tamu yang bermalam beberapa hari di rumahnya, agar si tamu tidak bosan dan merasa serasi (kerasan), d) dapat menghibur tamu selama 15 menit dengan beberapa macam acara (percakapan, nyanyian, permainan, sandiwara, lelucon, dan lain-lain)'),
(5, 10, 'Purwa', 'a) mengetahui nama suratkabar/majalah yang terbit di daerahnya, dan yang terbit di Jakarta, b) mengetahui jenis media masa yang dapat dipergunakan untuk usaha penerangan masyarakat, c) mengetahui cara dan telah menyusun suatu cerita tentang persitiwa yang baru saja terjadi dan menarik perhatian masyarakat, d) mengetahui cara dan telah membuat laporan tentang Perkemahan/ Lomba Penggalang/Perkemahan Wirakarya/Perpanitera/Permainan Besar Siaga/Kegiatan Pramuka lainnya, e) dapat menerangkan kepada orang lain tentang keadaan pasukannya/rencana kegiatan ambalannya, f) menunjukkan kemampuannya dalam mencatat peristiwa-peristiwa penting yang terjadi di daerahnya'),
(5, 10, 'Madya', 'a) telah mencapai TKK Juru Penerang Tingkat Purwa, b) dapat membuat berita pers (press release), c) dapat memelihara dan tahu penggunaan alat-alat penerangan kepada masyarakat tentang Keluarga Berencana atau Tabanas/ Taska, atau program Pemerintah di daerahnya, dan lain-lainnya, d) pernah menghadiri Rapat-Rapat atau Sidang DPR atau badan-badan lain, dan membuat laporan tertulis tentang hal tersebut'),
(5, 10, 'Utama', 'a) telah mencapai TKK Juru Penerang Tingkat Madya, b) dapat merencanakan dan mempersiapkan suatu acara jumpa pers/pers meeting, (untuk Penegak/Pandega harus dapat pula melaksanakannya) c) dapat memperbaiki kerusakan ringan alat-alat penerangan/ pemancar suara/ megafon, d) dapat menghibur tamu selama 15 menit dengan beberapa macam acara (percakapan, nyanyian, permainan, sandiwara, lelucon, dan lain-lain), e) pernah mengikuti secara aktif sistem tim penerangan di wilayahnya, f) mengetahui nama, alamat kantor berita dalam negeri/luar negeri'),
(5, 11, 'Purwa', 'a) dapat membuktikan bahwa ia mempunyai sahabat pena paling sedikit 3 orang dari kwartir daerah yang berlainan, b) mengetahui cara dan dapat menggunakan mesin ketik atau mengetahui dan dapat melaksanakan pencatatan surat-surat (agenda dan ekspedisi), c) dapat membuat surat-surat: 1) undangan, 2) ucapan terima kasih/belasungkawa, 3) pemberitahuan/izin, 4) pengumuman 5) telegram d) mengetahui cara dan dapat melaksanakan pengiriman: 1) uang poswesel, 2) berita telegram'),
(5, 11, 'Madya', 'a) telah mencapai TKK Korespondensi untuk Tingkat Purwa, b) dapat mengetik 10 jari, atau mengetahui dan dapat mengatur serta melaksanakan pekerjaan pengarsipan surat-surat, c) mengetahui tata cara dan dapat mengirimkan barang lewat pos (pospaket) atau dengan kereta/bis kilat, d) mengetahui cara dan membuat surat-surat memo, surat edaran, dan surat-surat resmi, e) dapat membuat berita pers (press release)'),
(5, 11, 'Utama', 'a) telah mencapai TKK Korespondensi Tingkat Madya, b) mempunyai sahabat pena dari negara lain, c) tahu cara mengirim berita lewat radio (RRI dan atau pemancar amatir), d) tahu cara pengiriman barang dan surat ke luar negeri lewat pos dan lewat kantor ekspedisi lain'),
(5, 12, 'Purwa', 'a) mengetahui cara dan dapat menolong kecelakaan luka iris, luka garuk, luka bakar/kena benda panas, benjut/memar, terkilir, hidung berdarah, tersengat/tergigit binatang berbisa, dan debu di mata, b) mengetahui cara dan dapat mencegah dan menolong orang yang mengalami hilang semangat (collapse), pingsan, matisuri (schijndood), dan tersengat sinar matahari (zonnesteek), c) mengetahui cara dan dapat menggunakan dengan benar dan rapih: pembalut segitiga (mitella), dan pembalut panjang (zwapchtel verband) untuk luka di jari, lengan, tangan, kepala, lutut dan betis, d) mengetahui letak urat-urat nadi terpenting, dan mengetahui cara penghentian pendarahan urat nadi, e) dapat membuat tandu darurat dengan cepat dan rapih, dan tahu serta dapat mengangkut penderita dengan berbagai cara, secara seorang diri maupun bersama dengan teman, f) mengetahui dan dapat melakukan dengan baik dua pernafasan tiruan (kunstmatige ademhaling), g) mempunyai pengetahuan tentang obat-obatan/ramuan yang dapat digunakan untuk pertolongan pertama pada kecelakaan, h) mengetahui nama, alamat, nomor telpon Puskesmas (poliklinik), rumah sakit, dan dokter setempat'),
(5, 12, 'Madya', 'a) telah mencapai TKK Pertolongan Pertama Pada Kecelakaan Tingkat Purwa, b) sebagai seorang anggota regu penolong (bukan pemimpin) yang terdiri atas 4 atau 5 orang, melakukan pertolongan pertama pada kecelakaan (tiruan) yang dibuat oleh penguji, secara terperinci, tepat, dan cepat sesuai dengan aturan PPPk (perlu diperhatikan keterangannya, kecepatan, kerjasama, dan lain-lain), c) mengetahui cara dan dapat menyampaikan secara lisan, tertulis atau melalui telpon (kepada dokter, rumahsakit, polisi atau keluarganya), d) mengetahui cara dan dapat melakukan dengan baik cara-cara pernafasan tiruan, e) mengetahui cara dan dapat mengangkut penderita melaui rintangan-rintangan (gang sempit, melalui kolong, menyeberang parit, melewati pagar/tembok, naik turun tangga, dan lain-lain) dengan atau tanpa tandu'),
(5, 12, 'Utama', 'a) telah mencapai TKK Pertolongaan Pertama Pada Kecelakaan Tingkat Madya, b) mengetahui cara dan dapat menolong kecelakaan berbagai macam patah tulang terbuka atau tertutup (fractura complicata dan incomplicata), juga rahang atau lutut meleset, c) mengetahui cara dan dapat memberi pertolongan kepada orang yang mengalami pendarahan dalam tubuh (interne bloedingen), d) dapat memperhatikan cara-cara bertindak apabila ada dugaan keracunan dan gegar otak, e) dapat dan tahu cara menolong orang tenggelam, terbenam/ tertimbun, kena aliran listrik, dan shock/gugat, f) pernah memimpin satu regu penolong pada kecelakaan (sungguh-sungguh atau tiruan)'),
(5, 13, 'Purwa', 'a) mengetahui seluk beluk padi, misalnya tentang jenis padi, pemilihan benih, pemilihan bibit, cara menanam, menyiang, pengaturan air, panenan, penyimpanan, dan lain-lain, b) tahu dan mengerti tentang upaya pemerintah/swasta, dalam hal pengelolaan padi, misalnya masalah penggilingan padi, catur saran wilayah unit desa, bimas, inmas, dan lain-lainnya. c) tahu dan kenal baik dengan Petugas Penyuluhan Pertanian Lapangan (PPPL), Mantri Pertanian Kecamatan, dan tokoh-tokoh pemuka pedesaan lainnya, d) sedikitnya telah dua kali membantu kegiatan penyuluhan pertanian'),
(5, 13, 'Madya', 'a) telah memenuhi SKK Penyuluh Padi Tingkat Purwa, b) mengerti seluk beluk pemberian dan penyimpanan pupuk untuk padi, hama/penyakit padi dan pemberantasannya, dan alat-alat yang digunakan untuk keperluan itu, c) mengetahui tentang Kontak Tani, Kelompok Tani, Gabungan Kelompok Tani, BUUD/KUD, serta kaitannya satu sama lain, d) sedikitnya telah dua kali ikut memberikan penjelasan/penerangan tentang pertanian kepada orang banyak, atau kepada satu kelompok pendengar siaran pedesaan'),
(5, 13, 'Utama', 'a) telah memenuhi SKK Penyuluh Padi Tingkat Madya, b) mengetahui masalah pengolahan tanah, dan penggunaan alat-alat pengolahan tanah, c) tahu dan mengerti beberapa metode penyuluhan pertanian di desanya, Catatan: Mengingat bahwa syarat untuk mencapai TKK Pembantu Penyuluh Padi sudah cukup berat, dan bahwa kegiatan memberikan penyuluhan kepada masyarakat sudah lebih berat daripada membina seorang Pramuka untuk mencapai TKK, maka pada SKK Pembantu Penyuluh Padi ini tidak dicantumkan syarat: telah membantu seorang Pramuka lain untuk mencapai TKK tersebut'),
(5, 14, 'Purwa', 'a) dapat mempraktekkan kepada diri sendiri atau orang lain bagaimana memberikan pertolongan terhadap luka bakar, kena pisau, kena benda tajam, dan kena sengatan binatang, b) mengerti yang disebut jungle survival (gladi tangguh di darat), c) pernah mengikuti kursus PPPK dan mendapatkan ijazah, d) dapat melaksanakan paling sedikit 5 macam pembalutan dengan pembalut segitiga, e) pernah berkemah dengan anggota regunya paling sedikit 2 kali, masing-masing sehari semalam dan membuat catatan yang telah dilakukan di dalam perkemahan tersebut, salah satu di antaranya adalah sebagai juru masak, f) mengerti tanaman, binatang, buah-buahan, dan sabagainya yang tidak boleh dimakan (dengan melihat tanda-tanda umumnya)'),
(5, 14, 'Madya', 'a) telah mencapai TKK Keadaan Darurat Penerbangan Tingkat Purwa, b) mempraktekkan bagi diri sendiri atau orang lain, bagaimana penyembuhan/ pertolongan terhadap pingsan karena kekurangan oksigen, pingsan karena muak, dan kedinginan, c) dapat melaksanakan pembalutan dengan segitiga dan dapat menggunakan bidai (spalk), pada siang maupun malam hari, d) melakukan penjelajahan (cross-coutry) paling sedikit 10 km, melalui hutan dan membuat laporan makanan-makanan yang diperolehnya di dalam hutan tersebut, e) pernah membantu PMI dalam upaya-upaya gerakan kemanusiaan, f) dapat menjelaskan keadaan kecelakaan dalam penerbangan di Indonesia minimal 2 kejadian yang pernah terjadi di Indonesia'),
(5, 14, 'Utama', 'a) telah mencapai TKK Keadaan Darurat Penerbangan Tingkat Madya, b) dapat melakukan penjelajahan (cross-country) paling sedikit 15 km melewati daerah hutan/gurun dengan melaksanakan perkemahan yang berpindah-pindah paling sedikit 3 kali perkemahan, c) tahu cara memberikan isyarat/tanda kepada pesawat terbang penolong yang mengatakan letak pesawat jatuh, semua penumpang dalam keadaan kelaparan dan membuat tanda arah angin, d) mengerti tanda pintu darurat di pesawat terbang dan cara membukanya, e) mengetahui kelengkapan pesawat terbang untuk keadaan darurat di laut, dan dapat menggunakannya, f) berdiskusi dengan Pembinanya tentang sebab suatu kecelakaan pesawat terbang dan mengetahui satuan SAR yang ada di Indonesia'),
(5, 15, 'Purwa', 'a) tahu bagaimana memberikan pertolongan terhadap bekas sengatan binatang, luka kena pisau, luka kena benda tajam yang lain, dan luka terbakar/kena api, b) mengerti apa yang disebut jungle survival dan sea survival (gladi tangguh di darat dan di laut), c) tahu tanaman, buah-buahan, binatang, dan sabagainya yang tidak boleh dimakan (dengan melihat tanda-tanda umumnya). d) pernah mengikuti kursus PPPK dan mendapatkan ijazah, e) dapat melaksanakan paling sedikit 5 macam pembalutan dengan pembalut segitiga, f) tahu cara pengarahan dari suatu tempat untuk pertolongan kecelakaan, g) pernah berkemah dengan anggota regunya paling sedikit 2 kali, masing-masing sehari semalam dan membuat catatan yang telah dilakukan di dalam perkemahan tersebut, salah satu di antaranya adalah sebagai juru masak'),
(5, 15, 'Madya', 'a) telah mencapai TKK Keadaan Darurat Laut Tingkat Purwa, b) tahu bagaimana memberikan pertolongan kepada orang pingsan karena matahari, pingsan karena kekurangan oksigen, pingsan karena muak, dan pingsan karena kedinginan (hypotermia), c) pernah mengadakan penjelajahan (cross-coutry/hiking) paling sedikit 10 km, melalui hutan dan membuat laporan termasuk makanan yang dapat diperolehnya di dalam hutan tersebut, d) telah memperoleh ijazah PPPK dari PMI atau lembaga lain yang sederajat/sah e) dapat melaksanakan pembalutan dengan segitiga dan dapat menggunakan bidai (spalk), pada siang maupun malam hari, serta mengangkut pasien dengan sepeda, kuda, sepeda motor, mobil, perahu layar, perahu dayung, motor boat, atau pesawat terbang f) pernah membantu PMI dalam upaya-upaya gerakan kemanusiaan'),
(5, 15, 'Utama', 'a) telah mencapai TKK Keadaan Darurat Laut Tingkat Madya, b) tahu cara memberikan pertolongan terhadap gigitan ular (tanpa ada obat-obatan), menggunakan bidai (spalk), bagaimana menyelamatkan dan memberikan pertolongan kepada orang-orang dalam kebakaran, c) pernah mengadakan penjelajahan (cross-country) paling sedikit 15 km melewati daerah hutan/gurun, dan dapat memberikan tanda isyarat bagi seorang tersesat untuk mendapatkan jalan kembali, d) masih berhak memegang ijazah PPPK dari PMI atau lembaga lain yang sederajat, e) berdiskusi dengan orang lain tergantung kejadian bahaya kebakaran/banjir/gempa bumi/arus panas dan membuat rencana pertolongan dengan pemerintahan setempat, f) dapat melaksanakan pengangkutan korban dengan paling sedikit 2 dari alat pengangkut dengan sepeda motor, mobil, motor boat atau pesawat, g) pernah ikut melaksanakan upaya menyelamatkan orang lain dari bahaya maut, atau menghibur orang lain yang menjadi korban bencana')
) as data(field_number, item_number, level, description)
join public.skk_items item on item.field_number = data.field_number and item.item_number = data.item_number
on conflict (skk_item_id, level) do update set description = excluded.description;

commit;

